      {/* collar */}
      <path d={`M${cx-7},70 Q${cx},78 ${cx+7},70`} fill="#0a1204"/>
      {/* chest stripe */}
      <line x1={bl} y1={84} x2={br} y2={84} stroke={acc} strokeWidth="1.5" opacity="0.25"/>
