const PROD_URL="https://purinstinct-app.vercel.app";
const BASE_URL=window.location.hostname==="localhost"?PROD_URL:window.location.origin;

function SessionPanel({rosters,players,allPlayers,activeRosterId,onActivate,onSetActiveRoster,onUpdateRoster,onAddPlayer,onCreateRoster,onDeleteRoster,onRemovePlayer,onOpenDossier,rosterCodes,onUpdateCodes,pendingSessions,onDismissPending,onPromotePending,onAddGroupToQueue}){
  const [editIdx,setEditIdx]=useState(null);
  const [addName,setAddName]=useState("");
  const [addGender,setAddGender]=useState("M");
  const [qrMap,setQrMap]=useState({});       // {rosterId: dataURL}
  const [activeQR,setActiveQR]=useState(null); // rosterId en vue QR
  const [expandedRosters,setExpandedRosters]=useState({}); // {rosterId: bool}
  const [acceptedIds,setAcceptedIds]=useState(new Set());

  const getCode=(id)=>(rosterCodes&&rosterCodes[id])||null;

  const generateCode=(id)=>{
    const code=String(Math.floor(1000+Math.random()*9000));
    onUpdateCodes&&onUpdateCodes({...(rosterCodes||{}),[id]:code});
    return code;
  };

  const generateQR=async(r,isPending=false)=>{
    let code=getCode(r.id)||generateCode(r.id);
    const url=`${BASE_URL}?session=${code}`;
    try{
      const dataUrl=await QRCode.toDataURL(url,{
        width:280,margin:2,
        color:{dark:"#000000",light:"#ffffff"},
        errorCorrectionLevel:"H"
      });
      setQrMap(prev=>({...prev,[r.id]:dataUrl}));
      setActiveQR(r.id);
      // Pointer l'admin vers ce roster sans réinitialiser les joueurs
      if(!isPending&&r.id!==activeRosterId&&onSetActiveRoster){
        onSetActiveRoster(r.id);
      }
      // Si session pending → la promouvoir dans les sessions régulières
      if(isPending&&onPromotePending){
        onPromotePending(r,code);
      }
    }catch(e){console.error(e);}
  };

  const downloadQR=(r)=>{
    const data=qrMap[r.id]; if(!data) return;
    const a=document.createElement("a");
    a.href=data; a.download=`QR-${r.name.replace(/\s+/g,"-")}.png`; a.click();
  };

  const handleAdd=()=>{
    const n=addName.trim();
    if(!n) return;
    onAddPlayer(n,addGender);
    setAddName("");
  };

  if(editIdx!==null){
    return(
      <RosterEditor
        roster={rosters[editIdx]}
        onSave={(updated)=>{onUpdateRoster(editIdx,updated);setEditIdx(null);}}
        onCancel={()=>setEditIdx(null)}
      />
    );
  }

  return(
    <div className="anim-up">
      {/* Current session */}
      <div style={{...S.card(),marginBottom:16,border:"1px solid #84cc1640"}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12}}>
          <div>
            <div style={{color:"#84cc16",fontWeight:700,fontSize:14}}>{T.fr.activeSession}</div>
            <div style={{color:"#6b7280",fontSize:12,marginTop:2}}>{players.length} {T.fr.playerCount}</div>
          </div>
          <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:28,color:"#84cc16"}}>{players.length}</div>
        </div>
        {/* Code + QR de la session active */}
        {(()=>{
          const activeCode=getCode(activeRosterId);
          const activeRoster=rosters.find(r=>r.id===activeRosterId);
          if(!activeCode&&!activeRoster) return null;
          return(
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",
              background:"#0d1508",borderRadius:12,padding:"10px 14px",marginBottom:12,
              border:"1px solid #84cc1640"}}>
              <div>
                <div style={{fontSize:10,color:"#4b5563",letterSpacing:2,textTransform:"uppercase",marginBottom:2}}>Code de la partie</div>
                {activeCode
                  ?<div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:36,
                      color:"#84cc16",letterSpacing:8,lineHeight:1}}>{activeCode}</div>
                  :<div style={{fontSize:12,color:"#4b5563"}}>Aucun code — générer dans les listes</div>}
              </div>
              {activeCode&&activeRoster&&(
                <button onClick={()=>generateQR(activeRoster)}
                  style={{...S.btn("#84cc16"),padding:"8px 14px",fontSize:13,fontWeight:700}}>
                  📲 QR
                </button>
              )}
            </div>
          );
        })()}
        {/* Joueurs de la session active seulement */}
        {players.length>0&&(
          <div style={{display:"flex",flexDirection:"column",gap:3,marginBottom:12,maxHeight:200,overflowY:"auto"}}>
            {[...players].sort((a,b)=>b.id-a.id).map(p=>(
              <div key={p.id} style={{...S.row(),gap:8,padding:"5px 10px",borderRadius:8,background:"#111827"}}>
                <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:13,
                  color:"#84cc16",width:22,flexShrink:0}}>#{p.number}</div>
                <span style={{color:"#fff",fontSize:12,flex:1}}>{p.name}</span>
                <span style={{fontSize:10,color:"#4b5563"}}>{p.gender==="F"?"F":"H"}</span>
                {onOpenDossier&&<button onClick={()=>onOpenDossier(p.id)}
                  style={{fontSize:10,padding:"2px 6px",borderRadius:6,border:"1px solid #374151",
                    background:"#1f2937",color:"#9ca3af",cursor:"pointer"}}>Profil</button>}
                {onRemovePlayer&&<button onClick={()=>{if(window.confirm("Supprimer "+p.name+" ?"))onRemovePlayer(p.id);}}
                  style={{fontSize:10,padding:"2px 6px",borderRadius:6,border:"1px solid #ef444440",
                    background:"#ef444415",color:"#ef4444",cursor:"pointer"}}
                  onMouseEnter={e=>e.currentTarget.style.background="#ef444430"}
                  onMouseLeave={e=>e.currentTarget.style.background="#ef444415"}>Supprimer</button>}
              </div>
            ))}
          </div>
        )}
        <div style={{...S.label(),marginBottom:8}}>{T.fr.addNow}</div>
        <div style={{display:"flex",gap:8}}>
          <input value={addName} onChange={e=>setAddName(e.target.value)}
            onKeyDown={e=>{if(e.key==="Enter")handleAdd();}}
            placeholder={T.fr.playerName}
            style={{flex:1,padding:"8px 12px",borderRadius:10,border:"1px solid #1f2937",background:"#06070f",color:"#fff",fontSize:13,outline:"none"}}/>
          <select value={addGender} onChange={e=>setAddGender(e.target.value)}
            style={{padding:"8px 10px",borderRadius:10,border:"1px solid #1f2937",background:"#06070f",color:"#9ca3af",fontSize:13,outline:"none"}}>
            <option value="M">H</option><option value="F">F</option>
          </select>
          <button onClick={handleAdd} style={{...S.btn("#84cc16"),padding:"8px 14px"}}>{T.fr.addBtn}</button>
        </div>
      </div>

      {/* Vue QR plein écran */}
      {activeQR&&qrMap[activeQR]&&(()=>{
        const r=rosters.find(x=>x.id===activeQR);
        const code=getCode(activeQR);
        const url=`${BASE_URL}?session=${code}`;
        return(
          <div style={{position:"fixed",inset:0,zIndex:60,background:"rgba(0,0,0,.92)",
            display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:20}}>
            <div style={{...S.card(),border:"2px solid #84cc1640",maxWidth:340,width:"100%",textAlign:"center"}}>
              <div style={{color:"#fff",fontWeight:700,fontSize:16,marginBottom:4}}>{r?.name}</div>
              <div style={{fontSize:12,color:"#4b5563",marginBottom:16}}>
                Code de partie : <span style={{color:"#84cc16",fontWeight:900,fontSize:22,
                  fontFamily:"'Barlow Condensed',sans-serif"}}>{code}</span>
              </div>
              <div style={{display:"inline-block",padding:12,background:"#fff",borderRadius:12,marginBottom:12}}>
                <img src={qrMap[activeQR]} alt="QR" style={{width:200,height:200,display:"block"}}/>
              </div>
              <div style={{fontSize:10,color:"#374151",marginBottom:14,wordBreak:"break-all",
                padding:"6px 10px",borderRadius:8,background:"#111827"}}>{url}</div>
              <div style={{display:"flex",gap:8,justifyContent:"center"}}>
                <button onClick={()=>downloadQR(r)}
                  style={{...S.btn("#84cc16"),padding:"10px 18px",fontSize:13}}>⬇ Télécharger</button>
                <button onClick={()=>{navigator.clipboard&&navigator.clipboard.writeText(url);}}
                  style={{...S.btn(),padding:"10px 14px",fontSize:13}}>📋 Lien</button>
                <button onClick={()=>setActiveQR(null)}
                  style={{...S.btn(),padding:"10px 14px",fontSize:13}}>✕</button>
              </div>
            </div>
          </div>
        );
      })()}

      {/* Sessions solo en attente */}
      {(()=>{
        const rosterIds=new Set(rosters.map(r=>r.id));
        const pending=(pendingSessions||[]).filter(s=>!rosterIds.has(s.id));
        if(pending.length===0) return null;
        return(
        <div style={{marginBottom:16}}>
          <div style={{...S.label(),marginBottom:10,color:"#f97316"}}>⏳ Sessions en attente de code ({pending.length})</div>
          <div style={{display:"flex",flexDirection:"column",gap:8}}>
            {pending.map(s=>{
              const code=getCode(s.id);
              return(
                <div key={s.id} style={{...S.card(),border:"2px solid #f9731640"}}>
                  <div style={{...S.row(),gap:10,marginBottom:10}}>
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{color:"#fff",fontWeight:700,fontSize:14}}>{s.name}</div>
                      <div style={{...S.row(),gap:8,marginTop:3}}>
                        <span style={{fontSize:11,color:"#4b5563"}}>{s.gender==="F"?"Femme":"Homme"}</span>
                        <span style={{fontSize:11,color:"#f97316"}}>Arrivé à {s.createdAt}</span>
                        {code&&<span style={{fontSize:16,color:"#84cc16",fontWeight:700,fontFamily:"'Barlow Condensed',sans-serif",letterSpacing:3}}>🔑 {code}</span>}
                      </div>
                    </div>
                    <button onClick={()=>onDismissPending&&onDismissPending(s.id)}
                      style={{background:"none",border:"none",cursor:"pointer",color:"#374151",fontSize:16}}
                      onMouseEnter={e=>e.target.style.color="#ef4444"}
                      onMouseLeave={e=>e.target.style.color="#374151"}>×</button>
                  </div>
                  {(()=>{
                    const groupPlayers=(allPlayers||[]).filter(p=>p.groupId===s.id);
                    return groupPlayers.length>0&&(
                      <div style={{fontSize:11,color:"#84cc16",marginBottom:8,fontWeight:600}}>
                        👥 {groupPlayers.length} joueur{groupPlayers.length>1?"s":""} dans cette session :&nbsp;
                        {groupPlayers.map(p=>p.name.split(" ")[0]).join(", ")}
                      </div>
                    );
                  })()}
                  <div style={{display:"flex",gap:6,marginBottom:6}}>
                    {onAddGroupToQueue&&<button onClick={(e)=>{
                        onAddGroupToQueue(s.id,s);
                        setAcceptedIds(prev=>new Set([...prev,s.id]));
                        e.currentTarget.textContent="✓ Accepté!";
                        e.currentTarget.style.background="#22c55e";
                        e.currentTarget.disabled=true;
                      }}
                      style={{...S.btn("#84cc16"),flex:1,padding:"8px",fontSize:12,color:"#000",fontWeight:700}}>
                      ✓ Accepter
                    </button>}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
        );
      })()}

      {/* Saved rosters */}
      <div style={{...S.label(),marginBottom:10}}>{T.fr.savedLists}</div>
      <div style={{display:"flex",flexDirection:"column",gap:8,marginBottom:12}}>
        {rosters.map((r,i)=>{
          const code=getCode(r.id);
          const livePlayers=(allPlayers||[]).filter(p=>p.groupId===r.id);
          const liveCount=livePlayers.length;
          // Membres complets = joueurs live + entrées template non encore activées
          const liveNames=new Set(livePlayers.map(p=>p.name.toLowerCase()));
          const templateOnly=(r.entries||[]).filter(e=>!liveNames.has(e.name.toLowerCase()));
          const totalCount=liveCount+templateOnly.length;
          const isActive=r.id===activeRosterId;
          const isAccepted=acceptedIds.has(r.id);
          return(
            <div key={r.id} className={isAccepted?"pulse-accepted":""} style={{...S.card(),border:"1px solid "+(isActive?"#84cc16":code?"#84cc1630":"#1f2937")}}>
              <div style={{...S.row(),gap:8,marginBottom:8,flexWrap:"wrap"}}>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{...S.row(),gap:6}}>
                    <div style={{color:"#fff",fontWeight:600,fontSize:14}}>{r.name}</div>
                    {isActive&&<span style={{fontSize:10,color:"#84cc16",fontWeight:700,padding:"1px 6px",borderRadius:6,background:"#84cc1620"}}>ACTIVE</span>}
                  </div>
                  <div style={{...S.row(),gap:8,marginTop:3}}>
                    <span style={{fontSize:11,color:"#4b5563"}}>{(r.entries||[]).length} dans template</span>
                    {liveCount>0&&<span style={{fontSize:11,color:"#84cc16",fontWeight:700}}>👥 {liveCount} inscrits</span>}
                    {code&&<span style={{fontSize:16,color:"#84cc16",fontFamily:"'Barlow Condensed',sans-serif",fontWeight:700,letterSpacing:3}}>🔑 {code}</span>}
                  </div>
                </div>
              </div>
              {totalCount>0&&(
                <div style={{marginBottom:8}}>
                  <button onClick={()=>setExpandedRosters(prev=>({...prev,[r.id]:!prev[r.id]}))}
                    style={{width:"100%",padding:"6px 10px",borderRadius:10,border:"1px solid #84cc1640",
                      background:"#0d1508",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
                    <span style={{fontSize:12,color:"#84cc16",fontWeight:700}}>
                      👥 {totalCount} membre{totalCount>1?"s":""}
                      {liveCount>0&&<span style={{fontSize:10,color:"#22c55e",marginLeft:6}}>({liveCount} inscrit{liveCount>1?"s":""})</span>}
                    </span>
                    <span style={{fontSize:11,color:"#4b5563"}}>{expandedRosters[r.id]?"▲ Masquer":"▼ Voir la liste"}</span>
                  </button>
                  {expandedRosters[r.id]&&(
                    <div style={{marginTop:4,background:"#111827",borderRadius:10,padding:"8px 10px",
                      display:"flex",flexDirection:"column",gap:3,maxHeight:200,overflowY:"auto"}}>
                      {livePlayers.sort((a,b)=>a.number-b.number).map(p=>(
                        <div key={p.id} style={{display:"flex",alignItems:"center",gap:8,padding:"3px 0",
                          borderBottom:"1px solid #1f2937"}}>
                          <span style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:13,
                            color:"#84cc16",width:24,flexShrink:0}}>#{p.number}</span>
                          <span style={{fontSize:12,color:"#fff",flex:1}}>{p.name}</span>
                          <span style={{fontSize:10,color:"#4b5563"}}>{p.gender==="F"?"F":"H"}</span>
                          {onOpenDossier&&<button onClick={()=>onOpenDossier(p.id)}
                            style={{fontSize:10,padding:"2px 6px",borderRadius:6,border:"1px solid #374151",
                              background:"#1f2937",color:"#9ca3af",cursor:"pointer"}}>Profil</button>}
                          {onRemovePlayer&&<button onClick={()=>{if(window.confirm("Supprimer "+p.name+" ?"))onRemovePlayer(p.id);}}
                            style={{fontSize:10,padding:"2px 6px",borderRadius:6,border:"1px solid #ef444440",
                              background:"#ef444415",color:"#ef4444",cursor:"pointer"}}
                            onMouseEnter={e=>e.currentTarget.style.background="#ef444430"}
                            onMouseLeave={e=>e.currentTarget.style.background="#ef444415"}>Supprimer</button>}
                        </div>
                      ))}
                      {templateOnly.map((e,i)=>(
                        <div key={"t"+i} style={{display:"flex",alignItems:"center",gap:8,padding:"3px 0",
                          borderBottom:"1px solid #1f2937",opacity:0.5}}>
                          <span style={{width:24,flexShrink:0,fontSize:11,color:"#4b5563"}}>—</span>
                          <span style={{fontSize:12,color:"#9ca3af",flex:1}}>{e.name}</span>
                          <span style={{fontSize:10,color:"#4b5563"}}>{e.gender==="F"?"F":"H"}</span>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}
              <div style={{display:"flex",gap:6,marginBottom:8}}>
                <button onClick={()=>setEditIdx(i)} style={{...S.btn(),flex:1,padding:"7px",fontSize:11}}>✏️ Modifier</button>
                <button onClick={()=>onActivate(i)} style={{...S.btn(isActive?"#374151":"#84cc16"),flex:1,padding:"7px",fontSize:11,opacity:isActive?0.5:1}}>{isActive?"✓ Active":"▶ Activer"}</button>
                <button onClick={()=>onDeleteRoster&&onDeleteRoster(i)}
                  style={{...S.btn("#ef444420"),flex:1,padding:"7px",fontSize:11,color:"#ef4444",border:"1px solid #ef444440"}}
                  onMouseEnter={e=>{e.currentTarget.style.background="#ef444430";}}
                  onMouseLeave={e=>{e.currentTarget.style.background="#ef444420";}}>
                  🗑 Supprimer
                </button>
              </div>
              <button onClick={()=>generateQR(r)}
                style={{...S.btn(code?"#111827":"#0d1508"),width:"100%",padding:"8px",fontSize:12,
                  border:"1px solid "+(code?"#374151":"#84cc1640"),color:code?"#6b7280":"#84cc16"}}>
                📲 {code?"Voir / Régénérer le QR":"Générer le QR code"}
              </button>
            </div>
          );
        })}
      </div>
      <button onClick={onCreateRoster}
        style={{...S.btn(),width:"100%",padding:"12px",fontSize:13,border:"1px dashed #374151"}}>
        {T.fr.newList}
      </button>
    </div>
  );
}


// ----------------------------------------------------------------
// PLAYER DOSSIER  (shared: admin + player view)
// ----------------------------------------------------------------
function ProgressChart({player}){
  const history=player.history||[];
  if(history.length===0) return null;

  const zoneColors={purinstinct:"#84cc16",speed:"#f97316",handAgility:"#3b82f6",
    footAgility:"#22c55e",generalAgility:"#eab308",iq:"#a855f7"};
  const zoneShort={purinstinct:"PurI.",speed:"Vitesse",handAgility:"Main",
    footAgility:"Pied",generalAgility:"Agilité",iq:"IQ"};

  const gpPoints=[0,...history.map(h=>h.gp||0)];
  const zsPoints={};
  ZK.forEach(zk=>{zsPoints[zk]=[50,...history.map(h=>h.zs?h.zs[zk]||50:50)];});

  const W=320, H=195, PAD_L=8, PAD_R=56, PAD_V=24, PAD_BOTTOM=20;
  const INNER_W=W-PAD_L-PAD_R, INNER_H=H-PAD_V-PAD_BOTTOM;
  const n=gpPoints.length;
  const xScale=(i)=>PAD_L+i*(INNER_W/(n-1||1));
  const lastX=xScale(n-1);

  // Grouper les entrées par date de séance (jour)
  const sessions=[];
  history.forEach((h,i)=>{
    const day=new Date(h.ts).toLocaleDateString("fr-CA",{day:"numeric",month:"short"});
    const idx=i+1; // +1 car gpPoints[0] est le point de départ
    if(sessions.length===0||sessions[sessions.length-1].label!==day){
      sessions.push({label:day,startIdx:idx,x:xScale(idx)});
    }
  });
  // Ajouter "Aujourd'hui" si la session actuelle a des entrées après le dernier historique passé
  const todayStr=new Date().toLocaleDateString("fr-CA",{day:"numeric",month:"short"});
  if(sessions.length===0||sessions[sessions.length-1].label!==todayStr){
    // Chercher si une entrée du jour existe
    const todayEntries=history.filter(h=>new Date(h.ts).toLocaleDateString("fr-CA",{day:"numeric",month:"short"})===todayStr);
    if(todayEntries.length>0){
      const firstIdx=history.indexOf(todayEntries[0])+1;
      sessions.push({label:"Auj.", startIdx:firstIdx,x:xScale(firstIdx),today:true});
    }
  }

  const maxGP=Math.max(...gpPoints,20);
  const gpY=(v)=>PAD_V+INNER_H-(v/maxGP)*INNER_H;
  const zsY=(v)=>PAD_V+INNER_H-(v/100)*INNER_H;

  const makePath=(pts,yFn)=>pts.map((v,i)=>(i===0?"M":"L")+xScale(i).toFixed(1)+","+yFn(v).toFixed(1)).join(" ");

  // Calcul des positions Y brutes des labels de zones
  const LABEL_H=10; // hauteur approximative d'une ligne de texte
  const MIN_GAP=LABEL_H+1;
  const rawLabels=ZK.map(zk=>({
    zk, color:zoneColors[zk], text:zoneShort[zk],
    rawY:zsY(zsPoints[zk][n-1])
  })).sort((a,b)=>a.rawY-b.rawY);

  // Algorithme anti-overlap : passe descendante puis remontante
  const adjustedY=[...rawLabels.map(l=>l.rawY)];
  // Passe vers le bas
  for(let i=1;i<adjustedY.length;i++){
    if(adjustedY[i]<adjustedY[i-1]+MIN_GAP) adjustedY[i]=adjustedY[i-1]+MIN_GAP;
  }
  // Passe vers le haut (clamp au bas du graphique)
  const maxLabelY=PAD_V+INNER_H;
  for(let i=adjustedY.length-1;i>=0;i--){
    if(adjustedY[i]>maxLabelY) adjustedY[i]=maxLabelY;
    if(i<adjustedY.length-1&&adjustedY[i]>adjustedY[i+1]-MIN_GAP)
      adjustedY[i]=adjustedY[i+1]-MIN_GAP;
  }
  // Clamp au haut
  const minLabelY=PAD_V;
  for(let i=0;i<adjustedY.length;i++){
    if(adjustedY[i]<minLabelY) adjustedY[i]=minLabelY;
    if(i>0&&adjustedY[i]<adjustedY[i-1]+MIN_GAP) adjustedY[i]=adjustedY[i-1]+MIN_GAP;
  }

  const gpLabelY=Math.max(PAD_V+4, gpY(gpPoints[n-1])-6);

  return(
    <div>
      <svg width="100%" viewBox={`0 0 ${W} ${H}`} style={{overflow:"visible"}}>
        {/* Grille horizontale */}
        {[0,0.5,1].map(t=>(
          <line key={t} x1={PAD_L} y1={PAD_V+INNER_H*(1-t)} x2={W-PAD_R} y2={PAD_V+INNER_H*(1-t)}
            stroke="#1f2937" strokeWidth="1"/>
        ))}
        {/* Lignes verticales + dates des séances */}
        {sessions.map((s,i)=>(
          <g key={i}>
            <line x1={s.x} y1={PAD_V} x2={s.x} y2={PAD_V+INNER_H}
              stroke={s.today?"#84cc16":"#374151"} strokeWidth="1" strokeDasharray={s.today?"none":"3 2"}
              strokeOpacity={s.today?0.6:0.5}/>
            <text x={s.x} y={PAD_V+INNER_H+12} textAnchor="middle"
              fill={s.today?"#84cc16":"#6b7280"} fontSize="8" fontWeight={s.today?"bold":"normal"}>
              {s.label}
            </text>
          </g>
        ))}
        {/* Lignes zones */}
        {ZK.map(zk=>(
          <path key={zk} d={makePath(zsPoints[zk],zsY)}
            fill="none" stroke={zoneColors[zk]} strokeWidth="1" strokeOpacity="0.5"
            strokeDasharray="3 2"/>
        ))}
        {/* Ligne GP */}
        <path d={makePath(gpPoints,gpY)}
          fill="none" stroke="#84cc16" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
        {/* Point GP */}
        <circle cx={lastX} cy={gpY(gpPoints[n-1])} r="3" fill="#84cc16"/>
        {/* Trait de connexion + label GP */}
        <line x1={lastX} y1={gpY(gpPoints[n-1])} x2={lastX+4} y2={gpLabelY+1}
          stroke="#84cc16" strokeWidth="0.7" strokeOpacity="0.5"/>
        <text x={lastX+6} y={gpLabelY+4} fill="#84cc16" fontSize="9" fontWeight="bold">
          {gpPoints[n-1]} pts
        </text>
        {/* Labels zones avec trait de connexion et position anti-overlap */}
        {rawLabels.map((l,i)=>{
          const lineEndY=l.rawY;
          const labelY=adjustedY[i];
          return(
            <g key={l.zk}>
              <line x1={lastX} y1={lineEndY} x2={lastX+4} y2={labelY+1}
                stroke={l.color} strokeWidth="0.7" strokeOpacity="0.4"/>
              <text x={lastX+6} y={labelY+4} fill={l.color} fontSize="8" opacity="0.85">
                {l.text}
              </text>
            </g>
          );
        })}
      </svg>
      <div style={{fontSize:10,color:"#374151",textAlign:"center",marginTop:4}}>
        {n-1} partie{n-1>1?"s":""} · pts globaux —— zones - - -
      </div>
    </div>
  );
}

function PlayerDossier({player,onSave,onBack,embedded}){
  const [form,setForm]=useState({
    name:player.name||"",gender:player.gender||"M",age:player.age||"",
    email:player.email||"",instagram:player.instagram||"",
    tiktok:player.tiktok||"",snapchat:player.snapchat||"",
    photoConsent:player.photoConsent||false,videoConsent:player.videoConsent||false,
    profilePhoto:player.profilePhoto||null,highlights:player.highlights||[],
  });
  const [newUrl,setNewUrl]=useState("");
  const [newCap,setNewCap]=useState("");
  const [saved,setSaved]=useState(false);
  const fileRef=useRef(null);
  const set=(k,v)=>setForm(f=>({...f,[k]:v}));

  const handlePhoto=(e)=>{
    const file=e.target.files[0]; if(!file) return;
    const reader=new FileReader();
    reader.onload=(ev)=>set("profilePhoto",ev.target.result);
    reader.readAsDataURL(file);
  };
  const addHl=()=>{
    if(!newUrl.trim()) return;
    set("highlights",[...form.highlights,{url:newUrl.trim(),cap:newCap.trim()}]);
    setNewUrl(""); setNewCap("");
  };
  const removeHl=(i)=>set("highlights",form.highlights.filter((_,j)=>j!==i));
  const handleSave=()=>{
    onSave({...player,...form});
    setSaved(true); setTimeout(()=>setSaved(false),2200);
  };

  const inp={width:"100%",padding:"8px 12px",borderRadius:10,border:"1px solid #1f2937",
    background:"#06070f",color:"#fff",fontSize:13,outline:"none"};

  const body=(
    <div style={{padding:embedded?0:16,display:"flex",flexDirection:"column",gap:12}}>

      {/* Photo + identity */}
      <div style={{...S.card(),display:"flex",gap:14,alignItems:"flex-start"}}>
        <div style={{flexShrink:0,display:"flex",flexDirection:"column",alignItems:"center",gap:6}}>
          <div onClick={()=>fileRef.current&&fileRef.current.click()} style={{
            width:80,height:80,borderRadius:16,overflow:"hidden",cursor:"pointer",
            background:"#111827",border:"2px solid #374151",
            display:"flex",alignItems:"center",justifyContent:"center"}}>
            {form.profilePhoto
              ?<img src={form.profilePhoto} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
              :<div style={{textAlign:"center"}}>
                <div style={{fontSize:28}}>👤</div>
                <div style={{fontSize:9,color:"#4b5563",marginTop:2}}>Ajouter photo</div>
              </div>}
          </div>
          <input ref={fileRef} type="file" accept="image/*" onChange={handlePhoto} style={{display:"none"}}/>
          {form.profilePhoto&&(
            <button onClick={()=>set("profilePhoto",null)}
              style={{fontSize:10,color:"#6b7280",background:"none",border:"none",cursor:"pointer"}}>Retirer</button>
          )}
          <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:26,
            color:"#84cc16",lineHeight:1}}>#{player.number}</div>
        </div>
        <div style={{flex:1,display:"flex",flexDirection:"column",gap:8}}>
          <div>
            <div style={{...S.label(),marginBottom:4}}>{T.fr.fullName}</div>
            <input value={form.name} onChange={e=>set("name",e.target.value)} style={inp}/>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:6}}>
            <div style={{gridColumn:"1/3"}}>
              <div style={{...S.label(),marginBottom:3}}>Sexe</div>
              <select value={form.gender} onChange={e=>set("gender",e.target.value)}
                style={{...inp,appearance:"none"}}>
                <option value="M">Masculin</option>
                <option value="F">Feminin</option>
                <option value="X">Autre / N/A</option>
              </select>
            </div>
            <div>
              <div style={{...S.label(),marginBottom:3}}>Age</div>
              <input type="number" min="5" max="99" value={form.age}
                onChange={e=>set("age",e.target.value)} placeholder="--" style={inp}/>
            </div>
          </div>
        </div>
      </div>

      {/* Consent toggles */}
      <div style={{...S.card()}}>
        <div style={{...S.label(),marginBottom:10}}>Consentements</div>
        {[["photoConsent","📷","Consentement photo","Autoriser la publication de photos"],
          ["videoConsent","🎬","Consentement video","Autoriser la publication de videos et highlights"]
        ].map(([k,ic,lbl,desc])=>(
          <div key={k} onClick={()=>set(k,!form[k])} style={{
            display:"flex",alignItems:"center",justifyContent:"space-between",
            padding:"10px 0",cursor:"pointer",
            borderBottom:"1px solid #111827"}}>
            <div>
              <div style={{color:"#fff",fontSize:13,fontWeight:600}}>{ic} {lbl}</div>
              <div style={{color:"#4b5563",fontSize:11,marginTop:2}}>{desc}</div>
            </div>
            <div style={{width:46,height:26,borderRadius:13,flexShrink:0,position:"relative",
              transition:"background .2s",background:form[k]?"#84cc16":"#1f2937"}}>
              <div style={{position:"absolute",top:3,width:20,height:20,borderRadius:"50%",
                background:"#fff",transition:"left .2s",left:form[k]?23:3}}/>
            </div>
          </div>
        ))}
      </div>

      {/* Contact + social */}
      <div style={{...S.card()}}>
        <div style={{...S.label(),marginBottom:10}}>Contact et reseaux sociaux</div>
        <div style={{display:"flex",flexDirection:"column",gap:8}}>
          {[["email","📧 Email","email@exemple.com"],
            ["instagram","📸 Instagram","@username"],
            ["tiktok","🎵 TikTok","@username"],
            ["snapchat","👻 Snapchat","username"]
          ].map(([k,lbl,ph])=>(
            <div key={k}>
              <div style={{...S.label(),marginBottom:3}}>{lbl}</div>
              <input value={form[k]||""} onChange={e=>set(k,e.target.value)}
                placeholder={ph} style={inp}/>
            </div>
          ))}
        </div>
      </div>

      {/* Graphique historique */}
      {(player.history||[]).length>0&&(
        <div style={{...S.card()}}>
          <div style={{...S.label(),marginBottom:12}}>📈 Progression en séance</div>
          <ProgressChart player={player}/>
        </div>
      )}

      {/* Historique des activités */}
      {(player.history||[]).length>0&&(
        <div style={{...S.card()}}>
          <div style={{...S.label(),marginBottom:10}}>Historique ({(player.history||[]).length})</div>
          <div style={{display:"flex",flexDirection:"column",gap:4}}>
            {[...(player.history||[])].reverse().map((h,i)=>{
              const zc=ZONES[h.zone];
              return(
                <div key={i} style={{...S.row(),padding:"8px 12px",borderRadius:10,
                  background:h.isWin?"#0d150899":"#1a060699",
                  border:"1px solid "+(h.isWin?zc.color+"30":"#dc262630")}}>
                  <span style={{fontSize:16,flexShrink:0}}>{zc.icon}</span>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:13,color:"#fff",fontWeight:600}}>{zc.name}</div>
                    <div style={{fontSize:11,color:"#4b5563",marginTop:1}}>
                      {h.isWin?"Victoire":h.isSecond?"2e place":"Défaite"}
                      {h.bonus?" · Bonus x1.5":""}
                      {h.newStreak>=2?" · Série "+h.newStreak+" 🔥":""}
                    </div>
                  </div>
                  <div style={{textAlign:"right",flexShrink:0}}>
                    <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:18,
                      color:h.delta>=0?"#84cc16":"#ef4444"}}>
                      {h.delta>0?"+":""}{h.delta} pts
                    </div>
                    {h.gp!==undefined&&<div style={{fontSize:10,color:"#4b5563"}}>{h.gp} total</div>}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      <button onClick={handleSave} style={{
        padding:"14px",borderRadius:14,border:"none",cursor:"pointer",width:"100%",
        fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:18,
        background:saved?"#22c55e":"#84cc16",color:"#000",transition:"background .3s"}}>
        {saved?T.fr.savedMsg:T.fr.saveBtn}
      </button>
    </div>
  );

  if(embedded) return body;

  return(
    <div style={{minHeight:"100vh",background:"#06070f",fontFamily:"'DM Sans',sans-serif"}}>
      <style>{FONTS}</style>
      <div style={{position:"sticky",top:0,zIndex:10,
        paddingTop:"calc(env(safe-area-inset-top) + 12px)",paddingBottom:"12px",paddingLeft:"16px",paddingRight:"16px",
        background:"#06070f",borderBottom:"1px solid #111827",
        display:"flex",alignItems:"center",gap:12}}>
        {onBack&&<button onClick={onBack} style={{...S.btn(),padding:"6px 12px",fontSize:12}}>{T.fr.back}</button>}
        <div style={{flex:1}}>
          <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:16,color:"#84cc16"}}>
            #{player.number}
          </div>
          <div style={{fontSize:11,color:"#4b5563"}}>{form.name}</div>
        </div>
        <button onClick={handleSave} style={{...S.btn(saved?"#22c55e":"#84cc16"),padding:"8px 16px"}}>
          {saved?T.fr.saveOK:T.fr.save}
        </button>
      </div>
      <div style={{overflowY:"auto"}}>{body}</div>
    </div>
  );
}

