function LangBtn({lang}){const t=T.fr;return(<button onClick={onLangToggle} style={{padding:"4px 10px",borderRadius:8,border:"1px solid #84cc1650",background:"#111a05",color:"#84cc16",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Barlow Condensed',sans-serif",letterSpacing:1}}>{t.langOther}</button>);}

function LangFooter({lang}){
  const tl=T.fr;
  return(
    <div style={{position:"sticky",bottom:0,zIndex:20,display:"flex",justifyContent:"center",
      padding:"8px 16px",background:"#06070fdd",backdropFilter:"blur(6px)",
      borderTop:"1px solid #1f293760"}}>
      <button onClick={onLangToggle} style={{
        display:"flex",alignItems:"center",gap:8,padding:"7px 18px",borderRadius:10,
        border:"1px solid #84cc1650",background:"#111a05",cursor:"pointer"}}>
        <span style={{fontSize:16}}>{"🇫🇷"}</span>
        <span style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:14,
          color:"#84cc16",letterSpacing:1}}>{tl.langOther}</span>
      </button>
    </div>
  );
}


function LoginView({players,queues,onLogin,disabledZones,onGoLive}){
  const [tab,setTab]=useState("roles");
  return(
    <div style={{minHeight:"100vh",display:"flex",flexDirection:"column",alignItems:"center",
      padding:"40px 16px",background:"#06070f",fontFamily:"'DM Sans',sans-serif"}}>
      <style>{FONTS}</style>
      <div className="anim-pop" style={{marginBottom:32,textAlign:"center"}}>
        <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:72,letterSpacing:-2,lineHeight:1}}>
          <span style={{color:"#84cc16"}}>PUR</span><span style={{color:"#fff"}}>INSTINCT</span>
        </div>
        <div style={{color:"#84cc16",fontSize:13,letterSpacing:3,textTransform:"uppercase",marginTop:4,fontWeight:700}}>
          PurInstinct Games
        </div>
        <div style={{color:"#4b5563",fontSize:11,letterSpacing:2,textTransform:"uppercase",marginTop:4,fontWeight:600}}>
          Jeux Sportifs
        </div>
      </div>

      <div style={{display:"flex",gap:4,padding:4,borderRadius:12,background:"#0d0f1a",marginBottom:24}}>
        {[["roles",T.fr.rolesTab],["players",T.fr.playersTab]].map(([t,l])=>(
          <button key={t} onClick={()=>setTab(t)} style={{
            padding:"8px 16px",borderRadius:8,fontSize:13,fontWeight:600,border:"none",cursor:"pointer",
            background:tab===t?"#84cc16":"transparent",color:tab===t?"#000":"#6b7280"}}>
            {l}
          </button>
        ))}
      </div>

      {tab==="roles"?(
        <div className="anim-up" style={{width:"100%",maxWidth:360,display:"flex",flexDirection:"column",gap:8}}>
          <button onClick={()=>onLogin("admin",null)} style={{width:"100%",padding:"16px 20px",borderRadius:16,
            border:"1px solid #1f2937",background:"#111827",color:"#fff",cursor:"pointer",
            display:"flex",alignItems:"center",gap:12,fontFamily:"'DM Sans',sans-serif"}}>
            <span style={{fontSize:22}}>🛡️</span>
            <div style={{textAlign:"left"}}>
              <div style={{fontWeight:700,fontSize:14}}>{T.fr.adminRole}</div>
              <div style={{color:"#6b7280",fontSize:12,fontWeight:400,marginTop:2}}>{T.fr.adminSub}</div>
            </div>
          </button>
          <div style={{...S.label(),textAlign:"center",paddingTop:12,paddingBottom:4}}>{T.fr.stationManagers}</div>
          {ZK.map(zk=>{
            const zl=zn(zk);
            const isOff=(disabledZones||[]).includes(zk);
            return(
            <button key={zk} onClick={()=>onLogin("station",zk)} style={{
              width:"100%",padding:"14px 16px",borderRadius:16,
              border:"1px solid "+(isOff?"#ef444440":ZONES[zk].border),
              background:isOff?"#1a0a0a":ZONES[zk].bg,
              color:isOff?"#ef4444":ZONES[zk].color,cursor:"pointer",
              display:"flex",alignItems:"center",gap:12,fontFamily:"'DM Sans',sans-serif",
              opacity:isOff?0.7:1,position:"relative"}}>
              <span style={{fontSize:22,opacity:isOff?0.5:1}}>{ZONES[zk].icon}</span>
              <div style={{textAlign:"left",flex:1}}>
                <div style={{fontWeight:700,fontSize:14}}>{zl.name}</div>
              </div>
              {isOff&&<span style={{fontSize:10,fontWeight:700,padding:"2px 8px",borderRadius:10,
                background:"#ef444420",color:"#ef4444",border:"1px solid #ef444440",flexShrink:0}}>
                DÉSACTIVÉE
              </span>}
            </button>
            );
          })}
        </div>
      ):(
        <div className="anim-up" style={{width:"100%",maxWidth:420}}>
          <div style={{textAlign:"center",marginBottom:20}}>
            <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:700,fontSize:13,color:"#4b5563",letterSpacing:3,textTransform:"uppercase",marginBottom:6}}>{T.fr.selectNumber}</div>

          </div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:6}}>
            {players.map(p=>{
              const inQ=Object.values(queues||{}).some(q=>Array.isArray(q)&&q.includes(p.id));
              const genderColor=p.gender==="F"?"#ec4899":"#3b82f6";
              const statusColor=inQ?"#f97316":"#84cc16";
              return(
                <button key={p.id} onClick={()=>onLogin("player",p.id)} style={{
                  aspectRatio:"1",borderRadius:14,
                  border:"1px solid "+(inQ?"#f9731640":genderColor+"30"),
                  background:inQ?"#1c0e00":"#0d0f1a",
                  cursor:"pointer",position:"relative",
                  display:"flex",flexDirection:"column",
                  alignItems:"center",justifyContent:"center",gap:3,
                  padding:4}}>
                  <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:24,color:"#fff",lineHeight:1}}>{p.number}</div>
                  <div style={{fontSize:8,color:"#6b7280",textAlign:"center",padding:"0 4px",lineHeight:1.2,maxWidth:"100%",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>
                    {p.name.split(" ")[0]}
                  </div>
                </button>
              );
            })}
          </div>
          <div style={{marginTop:14,padding:"8px 12px",borderRadius:10,background:"#0d0f1a",border:"1px solid #1f2937",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <span style={{fontSize:11,color:"#374151"}}>{players.length} {"joueurs"}</span>
            <span style={{fontSize:11,color:"#f97316"}}>{Object.values(queues||{}).flat().filter((v,i,a)=>a.indexOf(v)===i).length} {"en file"}</span>
          </div>
        </div>
      )}

      {/* Bouton Mode Live */}
      <div style={{marginTop:32,paddingTop:24,borderTop:"1px solid #1f2937",width:"100%",maxWidth:420,textAlign:"center"}}>
        <div style={{fontSize:11,color:"#374151",marginBottom:10,letterSpacing:1,textTransform:"uppercase"}}>Prêt pour une vraie session ?</div>
        <button onClick={onGoLive}
          style={{width:"100%",padding:"14px",borderRadius:16,border:"2px solid #84cc16",
            background:"linear-gradient(135deg,#111a05,#0d0f1a)",
            color:"#84cc16",cursor:"pointer",fontFamily:"'Barlow Condensed',sans-serif",
            fontWeight:900,fontSize:18,letterSpacing:1,
            boxShadow:"0 0 20px #84cc1620"}}
          onMouseEnter={e=>{e.currentTarget.style.background="#84cc16";e.currentTarget.style.color="#000";}}
          onMouseLeave={e=>{e.currentTarget.style.background="linear-gradient(135deg,#111a05,#0d0f1a)";e.currentTarget.style.color="#84cc16";}}>
          ⚡ Passer en mode LIVE
        </button>
        <div style={{fontSize:10,color:"#374151",marginTop:8}}>Expérience joueur simplifiée · Accès sécurisé par PIN</div>
      </div>
    </div>
  );
}

// ----------------------------------------------------------------
// LIVE LOGIN VIEW
// ----------------------------------------------------------------
const ADMIN_PIN="1111";
const STATION_PIN="2222";

function LiveLoginView({players,queues,onLogin,disabledZones,onGoTest,rosterCodes,onAddPlayer,onRequestSolo}){
  // Détecter le code de session dans l'URL (?session= ou ?code=)
  const _params=new URLSearchParams(window.location.search);
  const urlCode=_params.get("session")||_params.get("code")||null;

  // screen: "sessionCode" | "player" | "newPlayer" | "admin" | "station" | "stationPick"
  const [screen,setScreen]=useState(urlCode?"player":"sessionCode");
  const [sessionCode,setSessionCode]=useState(urlCode||"");
  const [sessionCodeError,setSessionCodeError]=useState(false);
  const [search,setSearch]=useState("");
  const [pin,setPin]=useState("");
  const [pinError,setPinError]=useState(false);
  const [newName,setNewName]=useState("");
  const [newGender,setNewGender]=useState("M");
  const [soloSubmitted,setSoloSubmitted]=useState(false);
  const [activeGroupId,setActiveGroupId]=useState("main");

  // Résoudre le groupId associé au code URL dès que rosterCodes est disponible
  useEffect(()=>{
    if(!urlCode||!rosterCodes) return;
    const entry=Object.entries(rosterCodes).find(([,v])=>v===urlCode);
    if(entry) setActiveGroupId(entry[0]);
  },[rosterCodes]);

  // Chercher dans TOUS les joueurs du code ET du groupe actif
  // (le code peut pointer vers un groupId différent des joueurs déjà inscrits)
  const groupPlayers=players.filter(p=>(p.groupId||"main")===activeGroupId);
  // Recherche dans tous les joueurs si le groupe est vide (fallback)
  const searchPool=groupPlayers.length>0?groupPlayers:players;
  const filtered=search.trim().length>0
    ?searchPool.filter(p=>p.name.toLowerCase().includes(search.toLowerCase())||String(p.number).includes(search))
    :[];

  const handleCreateSolo=()=>{
    if(!newName.trim()) return;
    onRequestSolo&&onRequestSolo(newName.trim(),newGender,(newId)=>{
      onLogin("player",newId);
    });
  };

  const handleAddToGroup=()=>{
    if(!newName.trim()) return;
    onAddPlayer&&onAddPlayer(newName.trim(),newGender,(newId)=>{
      onLogin("player",newId);
    },activeGroupId);
  };

  const handleAddToGroupWithName=(name)=>{
    if(!name.trim()) return;
    onAddPlayer&&onAddPlayer(name.trim(),newGender,(newId)=>{
      onLogin("player",newId);
    },activeGroupId);
  };

  // Valider le code de session
  const handleSessionCode=(code)=>{
    const c=code||sessionCode;
    if(c==="0000"){
      setScreen("newPlayer"); setSessionCodeError(false); return;
    }
    // Trouver le groupId associé au code
    if(rosterCodes){
      const entry=Object.entries(rosterCodes).find(([,v])=>v===c);
      if(entry){
        const rosterId=entry[0];
        setActiveGroupId(rosterId); // chaque code = son groupe isolé
        setScreen("player"); setSessionCodeError(false); return;
      }
    }
    setSessionCodeError(true);
    setSessionCode("");
  };

  // PIN Admin / Station
  const handlePinSubmit=(role,value)=>{
    const entered=value!==undefined?value:pin;
    const expected=role==="admin"?ADMIN_PIN:STATION_PIN;
    if(entered===expected){
      setPinError(false);
      if(role==="admin") onLogin("adminHome",null);
      else setScreen("stationPick");
    } else {
      setPinError(true); setPin("");
    }
  };

  // Clavier numérique réutilisable
  const NumPad=({value,onChange,onComplete,maxLen=4})=>(
    <div>
      <div style={{display:"flex",justifyContent:"center",gap:12,marginBottom:20}}>
        {Array.from({length:maxLen}).map((_,i)=>(
          <div key={i} style={{width:18,height:18,borderRadius:"50%",
            background:i<value.length?"#84cc16":"#1f2937",
            border:"2px solid "+(i<value.length?"#84cc16":"#374151")}}/>
        ))}
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10,maxWidth:260,margin:"0 auto"}}>
        {[1,2,3,4,5,6,7,8,9,"",0,"⌫"].map((k,i)=>(
          <button key={i} onClick={()=>{
            if(k==="") return;
            if(k==="⌫"){onChange(value.slice(0,-1));}
            else if(value.length<maxLen){
              const nv=value+k; onChange(nv);
              if(nv.length===maxLen) setTimeout(()=>onComplete(nv),150);
            }
          }} style={{padding:"16px",borderRadius:14,border:"1px solid #1f2937",
            background:k===""?"transparent":"#0d0f1a",color:"#fff",
            fontFamily:"'Barlow Condensed',sans-serif",fontWeight:700,fontSize:22,
            cursor:k===""?"default":"pointer",opacity:k===""?0:1,
            boxShadow:k!==""?"0 2px 8px rgba(0,0,0,.3)":"none"}}
            onMouseEnter={e=>{if(k!=="")e.currentTarget.style.background="#1f2937";}}
            onMouseLeave={e=>{if(k!=="")e.currentTarget.style.background="#0d0f1a";}}>
            {k}
          </button>
        ))}
      </div>
    </div>
  );

  const Header=()=>(
    <div style={{textAlign:"center",marginBottom:28}}>
      <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:64,letterSpacing:-2,lineHeight:1}}>
        <span style={{color:"#84cc16"}}>PUR</span><span style={{color:"#fff"}}>INSTINCT</span>
      </div>
      <div style={{color:"#84cc16",fontSize:12,letterSpacing:3,textTransform:"uppercase",marginTop:4,fontWeight:700}}>
        PurInstinct Games
      </div>
    </div>
  );

  return(
    <div style={{minHeight:"100vh",display:"flex",flexDirection:"column",alignItems:"center",
      justifyContent:"center",padding:"32px 16px",background:"#06070f",fontFamily:"'DM Sans',sans-serif"}}>
      <style>{FONTS}</style>
      {onGoTest&&<button onClick={onGoTest}
        style={{position:"fixed",bottom:16,right:16,fontSize:10,color:"#374151",
          background:"none",border:"1px solid #1f2937",borderRadius:8,padding:"4px 8px",cursor:"pointer"}}>
        Mode test
      </button>}

      <Header/>

      {/* ÉTAPE 1 — Code de session (si pas de QR) */}
      {screen==="sessionCode"&&(
        <div className="anim-up" style={{width:"100%",maxWidth:320}}>
          <div style={{textAlign:"center",marginBottom:20}}>
            <div style={{fontSize:32,marginBottom:8}}>🔑</div>
            <div style={{color:"#fff",fontWeight:700,fontSize:18,marginBottom:4}}>Code de session</div>
            <div style={{color:"#4b5563",fontSize:12}}>Entrez le code à 4 chiffres de votre session</div>
          </div>
          {sessionCodeError&&<div style={{textAlign:"center",color:"#ef4444",fontSize:12,marginBottom:12}}>
            Code invalide. Réessayez ou entrez <strong>0000</strong> pour une nouvelle session.
          </div>}
          <NumPad value={sessionCode} onChange={v=>{setSessionCode(v);setSessionCodeError(false);}}
            onComplete={handleSessionCode}/>
          <div style={{textAlign:"center",marginTop:16,fontSize:11,color:"#374151"}}>
            Entrez <span style={{color:"#84cc16",fontWeight:700}}>0000</span> pour démarrer une session solo
          </div>
          {/* Boutons Admin + Station discrets en bas */}
          <div style={{display:"flex",gap:8,marginTop:24,justifyContent:"center"}}>
            <button onClick={()=>{setScreen("admin");setPin("");setPinError(false);}}
              style={{padding:"8px 16px",borderRadius:10,border:"1px solid #374151",background:"#111827",
                color:"#6b7280",cursor:"pointer",fontSize:12,display:"flex",alignItems:"center",gap:6}}
              onMouseEnter={e=>e.currentTarget.style.borderColor="#84cc16"}
              onMouseLeave={e=>e.currentTarget.style.borderColor="#374151"}>
              🛡️ Admin
            </button>
            <button onClick={()=>{setScreen("station");setPin("");setPinError(false);}}
              style={{padding:"8px 16px",borderRadius:10,border:"1px solid #374151",background:"#111827",
                color:"#6b7280",cursor:"pointer",fontSize:12,display:"flex",alignItems:"center",gap:6}}
              onMouseEnter={e=>e.currentTarget.style.borderColor="#f97316"}
              onMouseLeave={e=>e.currentTarget.style.borderColor="#374151"}>
              📍 Station
            </button>
          </div>
        </div>
      )}

      {/* ÉTAPE 2b — Nouveau joueur solo (code 0000) */}
      {screen==="newPlayer"&&(
        <div className="anim-up" style={{width:"100%",maxWidth:360}}>
          {!soloSubmitted&&<button onClick={()=>{setScreen("sessionCode");setNewName("");setSoloSubmitted(false);}}
            style={{background:"none",border:"none",color:"#6b7280",fontSize:13,cursor:"pointer",marginBottom:20,padding:0}}>
            ← Retour
          </button>}

          {soloSubmitted?(
            /* Confirmation en attente */
            <div style={{textAlign:"center"}}>
              <div style={{fontSize:56,marginBottom:16}}>⏳</div>
              <div style={{color:"#fff",fontWeight:700,fontSize:20,marginBottom:8}}>
                Demande envoyée !
              </div>
              <div style={{color:"#84cc16",fontWeight:700,fontSize:16,marginBottom:12}}>{newName}</div>
              <div style={{color:"#6b7280",fontSize:13,lineHeight:1.6,marginBottom:24}}>
                Votre session est en attente.<br/>
                L'administrateur va créer votre session<br/>
                et vous fournir un code ou un QR code.
              </div>
              <div style={{...S.card(),border:"1px solid #84cc1630",textAlign:"left"}}>
                <div style={{fontSize:11,color:"#4b5563",marginBottom:6}}>EN ATTENTE DE VALIDATION</div>
                <div style={{color:"#fff",fontWeight:600}}>{newName}</div>
                <div style={{color:"#6b7280",fontSize:12}}>{newGender==="F"?"Femme":"Homme"}</div>
              </div>
            </div>
          ):(
            /* Formulaire */
            <div>
              <div style={{textAlign:"center",marginBottom:24}}>
                <div style={{fontSize:40,marginBottom:8}}>👤</div>
                <div style={{color:"#fff",fontWeight:700,fontSize:20,marginBottom:4}}>Nouvelle session</div>
                <div style={{color:"#4b5563",fontSize:13}}>Entrez votre nom complet</div>
              </div>
              <div style={{display:"flex",flexDirection:"column",gap:12}}>
                <input value={newName} onChange={e=>setNewName(e.target.value)}
                  onKeyDown={e=>{if(e.key==="Enter"&&newName.trim())handleCreateSolo();}}
                  placeholder="Prénom et nom"
                  autoFocus
                  style={{width:"100%",padding:"14px 16px",borderRadius:14,border:"2px solid #374151",
                    background:"#111827",color:"#fff",fontSize:16,outline:"none",boxSizing:"border-box"}}
                  onFocus={e=>e.target.style.borderColor="#84cc16"}
                  onBlur={e=>e.target.style.borderColor="#374151"}/>
                <div style={{display:"flex",gap:8}}>
                  {[["M","👨 Homme"],["F","👩 Femme"]].map(([v,l])=>(
                    <button key={v} onClick={()=>setNewGender(v)}
                      style={{flex:1,padding:"12px",borderRadius:12,
                        border:"2px solid "+(newGender===v?"#84cc16":"#374151"),
                        background:newGender===v?"#1a2e05":"#111827",
                        color:newGender===v?"#84cc16":"#6b7280",
                        cursor:"pointer",fontWeight:600,fontSize:14}}>
                      {l}
                    </button>
                  ))}
                </div>
                <button onClick={handleCreateSolo} disabled={!newName.trim()}
                  style={{padding:"14px",borderRadius:14,border:"none",cursor:newName.trim()?"pointer":"not-allowed",
                    background:newName.trim()?"#84cc16":"#1f2937",
                    color:newName.trim()?"#000":"#4b5563",
                    fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:18,
                    opacity:newName.trim()?1:0.5}}>
                  Envoyer ma demande
                </button>
              </div>
            </div>
          )}
        </div>
      )}

      {/* ÉTAPE 2 — Recherche joueur */}
      {screen==="player"&&(
        <div className="anim-up" style={{width:"100%",maxWidth:380}}>
          {!urlCode&&<button onClick={()=>{setScreen("sessionCode");setSearch("");}}
            style={{background:"none",border:"none",color:"#6b7280",fontSize:13,cursor:"pointer",marginBottom:16,padding:0}}>
            ← Retour
          </button>}
          {sessionCode&&<div style={{textAlign:"center",marginBottom:20}}>
            <div style={{fontSize:11,color:"#4b5563",letterSpacing:2,textTransform:"uppercase",marginBottom:4}}>Code de session</div>
            <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:52,color:"#84cc16",letterSpacing:6,lineHeight:1}}>{sessionCode}</div>
          </div>}
          <div style={{...S.card(),border:"1px solid #84cc1640",marginBottom:16}}>
            <div style={{fontSize:13,color:"#84cc16",fontWeight:700,marginBottom:12,textAlign:"center"}}>👤 Qui êtes-vous ?</div>
            <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Entrez votre nom ou numéro..." autoFocus
              style={{width:"100%",padding:"12px 14px",borderRadius:12,border:"1px solid #374151",
                background:"#111827",color:"#fff",fontSize:16,outline:"none",boxSizing:"border-box",marginBottom:search.trim()?10:0}}/>
            {filtered.length>0&&(
              <div style={{display:"flex",flexDirection:"column",gap:4,maxHeight:240,overflowY:"auto"}}>
                {filtered.map(p=>(
                  <button key={p.id} onClick={()=>onLogin("player",p.id)}
                    style={{...S.row(),gap:12,padding:"10px 12px",borderRadius:10,border:"1px solid #1f2937",
                      background:"#0d0f1a",cursor:"pointer",textAlign:"left"}}
                    onMouseEnter={e=>e.currentTarget.style.background="#1f2937"}
                    onMouseLeave={e=>e.currentTarget.style.background="#0d0f1a"}>
                    <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:22,
                      color:"#84cc16",width:32,textAlign:"center",flexShrink:0}}>#{p.number}</div>
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{color:"#fff",fontWeight:600,fontSize:14}}>{p.name}</div>
                      <div style={{color:"#4b5563",fontSize:11,marginTop:1}}>{p.globalPoints} pts · {(p.zonesPlayed||[]).length}/6 zones</div>
                    </div>
                    <div style={{color:"#374151",fontSize:16}}>›</div>
                  </button>
                ))}
              </div>
            )}
            {search.trim().length>0&&filtered.length===0&&(
              <div style={{marginTop:10}}>
                <div style={{textAlign:"center",color:"#4b5563",fontSize:12,marginBottom:12}}>
                  Aucun joueur trouvé pour <strong style={{color:"#fff"}}>"{search}"</strong>
                </div>
                <div style={{borderTop:"1px solid #1f2937",paddingTop:12}}>
                  <div style={{fontSize:12,color:"#6b7280",marginBottom:10,textAlign:"center"}}>
                    Vous n'êtes pas encore dans ce groupe ?
                  </div>
                  <div style={{display:"flex",gap:8,marginBottom:8}}>
                    {[["M","👨 Homme"],["F","👩 Femme"]].map(([v,l])=>(
                      <button key={v} onClick={()=>setNewGender(v)}
                        style={{flex:1,padding:"8px",borderRadius:10,
                          border:"2px solid "+(newGender===v?"#84cc16":"#374151"),
                          background:newGender===v?"#1a2e05":"#111827",
                          color:newGender===v?"#84cc16":"#6b7280",
                          cursor:"pointer",fontWeight:600,fontSize:12}}>
                        {l}
                      </button>
                    ))}
                  </div>
                  <button onClick={()=>{setNewName(search);handleAddToGroupWithName(search);}}
                    style={{width:"100%",padding:"10px",borderRadius:10,border:"none",cursor:"pointer",
                      background:"#84cc16",color:"#000",fontFamily:"'Barlow Condensed',sans-serif",
                      fontWeight:900,fontSize:15}}>
                    + Rejoindre comme "{search}"
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}

      {/* PIN Admin */}
      {screen==="admin"&&(
        <div style={{width:"100%",maxWidth:320}}>
          <button onClick={()=>{setScreen("sessionCode");setPin("");setPinError(false);}}
            style={{background:"none",border:"none",color:"#6b7280",fontSize:13,cursor:"pointer",marginBottom:20,padding:0}}>← Retour</button>
          <div style={{textAlign:"center",marginBottom:24}}>
            <div style={{fontSize:32,marginBottom:8}}>🛡️</div>
            <div style={{color:"#fff",fontWeight:700,fontSize:18}}>Accès Administrateur</div>
            <div style={{color:"#4b5563",fontSize:12,marginTop:4}}>Entrez votre code PIN</div>
          </div>
          {pinError&&<div style={{textAlign:"center",color:"#ef4444",fontSize:12,marginBottom:12}}>Code incorrect.</div>}
          <NumPad value={pin} onChange={v=>{setPin(v);setPinError(false);}} onComplete={v=>handlePinSubmit("admin",v)}/>
        </div>
      )}

      {/* PIN Station */}
      {screen==="station"&&(
        <div style={{width:"100%",maxWidth:320}}>
          <button onClick={()=>{setScreen("sessionCode");setPin("");setPinError(false);}}
            style={{background:"none",border:"none",color:"#6b7280",fontSize:13,cursor:"pointer",marginBottom:20,padding:0}}>← Retour</button>
          <div style={{textAlign:"center",marginBottom:24}}>
            <div style={{fontSize:32,marginBottom:8}}>📍</div>
            <div style={{color:"#fff",fontWeight:700,fontSize:18}}>Accès Responsable de station</div>
            <div style={{color:"#4b5563",fontSize:12,marginTop:4}}>Entrez votre code PIN</div>
          </div>
          {pinError&&<div style={{textAlign:"center",color:"#ef4444",fontSize:12,marginBottom:12}}>Code incorrect.</div>}
          <NumPad value={pin} onChange={v=>{setPin(v);setPinError(false);}} onComplete={v=>handlePinSubmit("station",v)}/>
        </div>
      )}

      {/* Choix station */}
      {screen==="stationPick"&&(
        <div className="anim-up" style={{width:"100%",maxWidth:380}}>
          <button onClick={()=>setScreen("station")}
            style={{background:"none",border:"none",color:"#6b7280",fontSize:13,cursor:"pointer",marginBottom:20,padding:0}}>← Retour</button>
          <div style={{color:"#fff",fontWeight:700,fontSize:16,marginBottom:16,textAlign:"center"}}>📍 Choisissez votre station</div>
          <div style={{display:"flex",flexDirection:"column",gap:8}}>
            {ZK.map(zk=>{
              const z=ZONES[zk]; const zl=zn(zk);
              const isOff=(disabledZones||[]).includes(zk);
              return(
                <button key={zk} onClick={()=>onLogin("station",zk)}
                  style={{padding:"14px 16px",borderRadius:14,border:"1px solid "+(isOff?"#ef444440":z.border),
                    background:isOff?"#1a0a0a":z.bg,color:isOff?"#ef4444":z.color,cursor:"pointer",
                    display:"flex",alignItems:"center",gap:12,opacity:isOff?0.7:1}}
                  onMouseEnter={e=>{if(!isOff)e.currentTarget.style.borderColor=z.color;}}
                  onMouseLeave={e=>{e.currentTarget.style.borderColor=isOff?"#ef444440":z.border;}}>
                  <span style={{fontSize:22}}>{z.icon}</span>
                  <span style={{fontWeight:700,fontSize:14,flex:1,textAlign:"left"}}>{zl.name}</span>
                  {isOff&&<span style={{fontSize:10,fontWeight:700,padding:"2px 8px",borderRadius:10,
                    background:"#ef444420",color:"#ef4444",border:"1px solid #ef444440"}}>DÉSACTIVÉE</span>}
                </button>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

// ----------------------------------------------------------------
// ADMIN VIEW
// ----------------------------------------------------------------
// ----------------------------------------------------------------
function AdminView({players,allPlayers,queues,activeGames,arenaState,rosters,activeRosterId,initialTab,onStart,onEnd,onPause,onResume,onUpdateDuration,onGoStation,onToggleZone,onAddQ,onRemoveQ,onAddGroupToQueue,onLogout,onActivateRoster,onSetActiveRoster,onUpdateRoster,onDeleteRoster,onAddPlayer,onCreateRoster,onUpdatePlayer,onRemovePlayer,winnersPublished,onPublishWinners,onUnpublishWinners,rosterCodes,onUpdateCodes,pendingSessions,onDismissPending,onPromotePending}){
  const [tab,setTab]=useState(initialTab||"leaderboard");
  const [sessionMins,setSessionMins]=useState(arenaState.sessionMins||75);
  const [timer,setTimer]=useState("75:00");
  const [dossierPlayerId,setDossierPlayerId]=useState(null);
  const [dossierOrigin,setDossierOrigin]=useState(null);
  const [selectedStation,setSelectedStation]=useState(null);
  const [stationTab,setStationTab]=useState("live");
  const [winnerCard,setWinnerCard]=useState(null); // {type:"overall"|"top5"|"zone", zk?}
  const [savingCard,setSavingCard]=useState(false);
  const cardRef=useRef(null);
  const [leaderSearch,setLeaderSearch]=useState("");
  const [leaderHighlight,setLeaderHighlight]=useState(null);
  const leaderHighlightRef=useRef(null);

  const openDossier=(id)=>{
    setDossierOrigin({tab,station:selectedStation});
    setDossierPlayerId(id);
  };

  const dossierPlayer = dossierPlayerId ? players.find(p=>p.id===dossierPlayerId) : null;


  useEffect(()=>{
    const totalSecs=(arenaState.sessionMins||75)*60;
    const fmt=(s)=>String(Math.floor(s/60)).padStart(2,"0")+":"+String(Math.floor(s%60)).padStart(2,"0");
    if(!arenaState.active&&!arenaState.paused){setTimer(fmt(totalSecs));return;}
    if(arenaState.paused){setTimer(fmt(arenaState.pausedRemaining||totalSecs));return;}
    const tick=()=>{
      const rem=Math.max(0,totalSecs-(Date.now()-arenaState.startTime)/1000);
      setTimer(fmt(rem));
    };
    tick(); const iv=setInterval(tick,1000); return()=>clearInterval(iv);
  },[arenaState]);

  const sorted=[...players].sort((a,b)=>b.globalPoints-a.globalPoints);
  const eligible=sorted.filter(p=>(p.zonesPlayed||[]).length===6);
  const winner=arenaState.ended&&eligible.length>0?eligible[0]:null;
  const timerColor=arenaState.active?"#84cc16":arenaState.paused?"#f97316":arenaState.ended?"#dc2626":"#374151";

  if(dossierPlayer) return(
    <PlayerDossier player={dossierPlayer}
      onSave={(updated)=>{onUpdatePlayer(updated);}}
      onBack={()=>{setDossierPlayerId(null);if(dossierOrigin){setTab(dossierOrigin.tab);setSelectedStation(dossierOrigin.station);}setDossierOrigin(null);}}/>
  );

  return(
    <div style={{minHeight:"100vh",background:"#06070f",fontFamily:"'DM Sans',sans-serif"}}>
      <style>{FONTS}</style>

      {winner&&(
        <div style={{position:"fixed",inset:0,zIndex:50,display:"flex",alignItems:"center",justifyContent:"center",
          padding:16,background:"rgba(0,0,0,.85)",backdropFilter:"blur(10px)"}}>
          <div className="anim-pop" style={{borderRadius:24,padding:32,textAlign:"center",maxWidth:320,width:"100%",
            background:"#0d1508",border:"2px solid #84cc16",boxShadow:"0 0 80px #84cc1630"}}>
            <div style={{fontSize:56,marginBottom:12}}>🏆</div>
            <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:22,color:"#fff",marginBottom:4}}>{T.fr.champion}</div>
            <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:52,color:"#84cc16"}}>#{winner.number}</div>
            <div style={{fontSize:18,fontWeight:700,color:"#fff",margin:"4px 0"}}>{winner.name}</div>
            <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:40,color:"#84cc16",marginBottom:16}}>{winner.globalPoints} pts</div>
            <div style={{display:"flex",justifyContent:"center",gap:4}}>{ZK.map(zk=><ZonePip key={zk} zone={zk} played={true}/>)}</div>
          </div>
        </div>
      )}

      <div style={{position:"sticky",top:0,zIndex:10,paddingTop:"calc(env(safe-area-inset-top) + 16px)",paddingBottom:"12px",paddingLeft:"16px",paddingRight:"16px",background:"#06070f",borderBottom:"1px solid #111827"}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12}}>
          <div>
            <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:18,color:"#fff"}}>ADMIN</div>
            <div style={{fontSize:11,color:"#4b5563"}}>{eligible.length} eligible{eligible.length!==1?"s":""} / {sorted.length} joueurs</div>
          </div>
          <div style={{display:"flex",alignItems:"center",gap:8}}>
            <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:2}}>
              <select value={sessionMins} onChange={e=>{
                  const m=Number(e.target.value);
                  setSessionMins(m);
                  if(arenaState.active) onUpdateDuration(m);
                }}
                style={{background:"#111827",color:"#d1d5db",border:"1px solid #374151",borderRadius:8,padding:"3px 6px",fontSize:11,cursor:"pointer"}}>
                {[30,45,60,75,90,120].map(m=><option key={m} value={m}>{m} min</option>)}
              </select>
              <div className={arenaState.active?"pulse-lime":""} style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:22,color:timerColor,lineHeight:1}}>{timer}</div>
              <div style={{fontSize:9,color:"#4b5563"}}>{arenaState.active?T.fr.active:arenaState.paused?"EN PAUSE":arenaState.ended?T.fr.ended:T.fr.waiting}</div>
            </div>
            {!arenaState.active&&!arenaState.paused&&<button onClick={()=>onStart(sessionMins)} style={{...S.btn("#84cc16"),padding:"6px 12px",fontSize:12}}>{T.fr.start}</button>}
            {arenaState.active&&<button onClick={onPause} style={{...S.btn("#f97316"),padding:"6px 12px",fontSize:12,color:"#000",fontWeight:700}}>⏸ Pause</button>}
            {arenaState.paused&&<button onClick={onResume} style={{...S.btn("#84cc16"),padding:"6px 12px",fontSize:12,color:"#000",fontWeight:700}}>▶ Reprendre</button>}
            {(arenaState.active||arenaState.paused)&&<button onClick={onEnd} style={{...S.btn("#dc2626"),padding:"6px 12px",fontSize:12,color:"#fff"}}>■ Terminer</button>}
            <button onClick={onGoStation} title="Mode responsable de plateau"
              style={{padding:8,borderRadius:10,background:"#111827",color:"#84cc16",border:"1px solid #84cc1640",cursor:"pointer",fontSize:15}}>📍</button>
            <button onClick={onLogout} style={{padding:8,borderRadius:10,background:"#111827",color:"#6b7280",border:"none",cursor:"pointer",fontSize:16}}>×</button>
          </div>
        </div>
        <div style={{display:"flex",gap:4}}>
          {[["leaderboard",T.fr.tabLeader],["stations",T.fr.tabStations],["players",T.fr.tabPlayers],["session",T.fr.tabSession],["winners","🥇 Gagnants"]].map(([t,l])=>(
            <button key={t} onClick={()=>{setTab(t);setSelectedStation(null);}} style={{
              padding:"6px 10px",borderRadius:8,fontSize:11,fontWeight:600,border:"none",cursor:"pointer",
              background:tab===t?"#84cc16":"#0d0f1a",color:tab===t?"#000":"#6b7280"}}>
              {l}
            </button>
          ))}
        </div>
      </div>

      <div style={{padding:16}}>
        {tab==="leaderboard"&&(
          <div className="anim-up">
            <div style={{...S.row(),justifyContent:"space-between",marginBottom:12}}>
              <div style={{...S.label()}}>{T.fr.realtimeRank}</div>
              <div style={{fontSize:11,color:"#4b5563"}}><span style={{color:"#84cc16"}}>✓</span> = 6/6 {T.fr.eligible}</div>
            </div>
            {/* Barre de recherche */}
            <div style={{position:"relative",marginBottom:10}}>
              <input value={leaderSearch} onChange={e=>{setLeaderSearch(e.target.value);setLeaderHighlight(null);}}
                placeholder="🔍 Rechercher un joueur..."
                style={{width:"100%",padding:"8px 12px",borderRadius:10,border:"1px solid #374151",
                  background:"#0d0f1a",color:"#fff",fontSize:16,outline:"none",boxSizing:"border-box"}}/>
              {leaderSearch.trim().length>0&&(()=>{
                const q=leaderSearch.trim().toLowerCase();
                const matches=sorted.filter(p=>p.name.toLowerCase().includes(q));
                if(matches.length===0) return null;
                return(
                  <div style={{position:"absolute",top:"100%",left:0,right:0,zIndex:10,
                    background:"#111827",border:"1px solid #374151",borderRadius:10,marginTop:4,
                    maxHeight:180,overflowY:"auto",boxShadow:"0 8px 24px rgba(0,0,0,.5)"}}>
                    {matches.map(p=>(
                      <div key={p.id} onClick={()=>{
                        setLeaderHighlight(p.id);
                        setLeaderSearch("");
                        setTimeout(()=>{leaderHighlightRef.current&&leaderHighlightRef.current.scrollIntoView({behavior:"smooth",block:"center"});},100);
                      }} style={{...S.row(),gap:10,padding:"8px 12px",cursor:"pointer",borderBottom:"1px solid #1f2937"}}
                        onMouseEnter={e=>e.currentTarget.style.background="#1f2937"}
                        onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                        <Bib n={p.number} size="sm"/>
                        <span style={{color:"#fff",fontSize:13,flex:1}}>{p.name}</span>
                        <span style={{color:"#84cc16",fontSize:12,fontWeight:700}}>#{sorted.indexOf(p)+1}</span>
                      </div>
                    ))}
                  </div>
                );
              })()}
            </div>
            <div style={{display:"flex",flexDirection:"column",gap:2}}>
              {sorted.map((p,i)=>(
                <div key={p.id} ref={p.id===leaderHighlight?leaderHighlightRef:null}>
                  <LeaderRow player={p} rank={i+1}
                    highlight={p.id===leaderHighlight}
                    onOpen={()=>openDossier(p.id)}/>
                </div>
              ))}
            </div>
            {leaderHighlight&&<button onClick={()=>setLeaderHighlight(null)}
              style={{marginTop:8,fontSize:11,color:"#4b5563",background:"none",border:"none",cursor:"pointer"}}>
              Effacer la surbrillance
            </button>}
          </div>
        )}

        {tab==="stations"&&(
          <div className="anim-up" style={{display:"flex",flexDirection:"column",gap:10}}>
            {selectedStation?(()=>{
              const zk=selectedStation; const z=ZONES[zk]; const zl=zn(zk);
              const game=activeGames[zk]; const q=queues[zk]||[];
              const teamA=game?(game.teamA||[]).map(id=>players.find(p=>p.id===id)).filter(Boolean):[];
              const teamB=game?(game.teamB||[]).map(id=>players.find(p=>p.id===id)).filter(Boolean):[];
              const solo=game?(game.participants||[]).map(id=>players.find(p=>p.id===id)).filter(Boolean):[];
              const inQueue=q.map(id=>players.find(p=>p.id===id)).filter(Boolean);
              return(
                <div>
                  {/* Header */}
                  <div style={{...S.row(),gap:10,marginBottom:12}}>
                    <button onClick={()=>{setSelectedStation(null);setStationTab("live");}}
                      style={{background:"none",border:"none",cursor:"pointer",color:"#6b7280",fontSize:20,lineHeight:1,padding:0}}
                      onMouseEnter={e=>e.target.style.color="#fff"}
                      onMouseLeave={e=>e.target.style.color="#6b7280"}>←</button>
                    <span style={{fontSize:22}}>{z.icon}</span>
                    <div style={{flex:1}}>
                      <div style={{color:"#fff",fontWeight:700,fontSize:16}}>{zl.name}</div>
                    </div>
                  </div>

                  {/* Onglets */}
                  <div style={{display:"flex",gap:4,marginBottom:14}}>
                    {[["live","⚡ Live"],["rules","📋 Règlements"]].map(([t,l])=>(
                      <button key={t} onClick={()=>setStationTab(t)}
                        style={{padding:"6px 14px",borderRadius:8,fontSize:11,fontWeight:600,border:"none",cursor:"pointer",
                          background:stationTab===t?z.color:"#0d0f1a",
                          color:stationTab===t?"#000":"#6b7280"}}>
                        {l}
                      </button>
                    ))}
                  </div>

                  {stationTab==="rules"&&(
                    <RulesCard zone={zk}/>
                  )}

                  {stationTab==="live"&&<>

                  {/* Live game */}
                  {game?(
                    <div style={{...S.card(),border:"1px solid "+z.border,marginBottom:10}}>
                      <div style={{...S.row(),justifyContent:"space-between",marginBottom:12}}>
                        <div style={{fontWeight:700,fontSize:13,color:"#fff"}}>Partie en cours</div>
                        <div className="pulse-lime" style={{...S.tag("#dc2626")}}>LIVE</div>
                      </div>
                      {solo.length>0?(
                        <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
                          {solo.map(p=>(
                            <div key={p.id} onClick={()=>openDossier(p.id)}
                              style={{...S.row(),gap:6,padding:"6px 10px",borderRadius:10,background:"#0d0f1a",
                                border:"1px solid "+z.color+"40",cursor:"pointer"}}
                              onMouseEnter={e=>e.currentTarget.style.borderColor=z.color}
                              onMouseLeave={e=>e.currentTarget.style.borderColor=z.color+"40"}>
                              <Bib n={p.number} size="sm"/>
                              <span style={{color:"#fff",fontSize:13,fontWeight:600,flex:1,minWidth:0,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{p.name.split(" ")[0]}</span>
                              <div style={{display:"flex",alignItems:"center",gap:4,flexShrink:0}}>
                                {(p.zoneStreaks&&p.zoneStreaks[zk]>=2)&&<span style={{fontSize:11,color:"#f97316"}}>🔥×{p.zoneStreaks[zk]}</span>}
                                <span style={{color:z.color,fontSize:13,fontWeight:700}}>{z.icon} {p.zoneScores[zk]||50}</span>
                              </div>
                            </div>
                          ))}
                        </div>
                      ):(
                        <div style={{display:"flex",gap:10}}>
                          {[["A",teamA],["B",teamB]].map(([label,team])=>(
                            <div key={label} style={{flex:1,background:"#0d0f1a",borderRadius:10,padding:"10px 12px",border:"1px solid "+z.color+"30"}}>
                              <div style={{color:z.color,fontWeight:700,fontSize:12,marginBottom:8}}>ÉQUIPE {label}</div>
                              {team.map(p=>(
                                <div key={p.id} onClick={()=>openDossier(p.id)}
                                  style={{...S.row(),gap:6,padding:"4px 0",cursor:"pointer",borderRadius:6}}
                                  onMouseEnter={e=>e.currentTarget.style.background="#ffffff08"}
                                  onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                                  <Bib n={p.number} size="sm"/>
                                  <span style={{color:"#fff",fontSize:13,fontWeight:600,flex:1,minWidth:0,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{p.name.split(" ")[0]}</span>
                                  <div style={{display:"flex",alignItems:"center",gap:4,flexShrink:0}}>
                                    {(p.zoneStreaks&&p.zoneStreaks[zk]>=2)&&<span style={{fontSize:11,color:"#f97316"}}>🔥×{p.zoneStreaks[zk]}</span>}
                                    <span style={{color:z.color,fontSize:13,fontWeight:700}}>{z.icon} {p.zoneScores[zk]||50}</span>
                                  </div>
                                </div>
                              ))}
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  ):(
                    <div style={{...S.card(),border:"1px solid #1f2937",marginBottom:10,textAlign:"center",color:"#4b5563",fontSize:13,padding:"20px 12px"}}>
                      Aucune partie en cours
                    </div>
                  )}

                  {/* Queue */}
                  <div style={{...S.card(),border:"1px solid #1f2937"}}>
                    <div style={{fontWeight:700,fontSize:13,color:"#fff",marginBottom:10}}>File d'attente ({inQueue.length})</div>
                    {inQueue.length===0?(
                      <div style={{color:"#4b5563",fontSize:12,textAlign:"center",padding:"8px 0"}}>File vide</div>
                    ):(
                      <div style={{display:"flex",flexDirection:"column",gap:4}}>
                        {inQueue.map((p,i)=>(
                          <div key={p.id} onClick={()=>openDossier(p.id)}
                            style={{...S.row(),gap:8,padding:"5px 8px",borderRadius:8,cursor:"pointer"}}
                            onMouseEnter={e=>e.currentTarget.style.background="#ffffff08"}
                            onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                            <span style={{color:"#4b5563",fontSize:11,width:16,textAlign:"right"}}>{i+1}</span>
                            <Bib n={p.number} size="sm"/>
                            <span style={{color:"#fff",fontSize:13,fontWeight:600,flex:1,minWidth:0,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{p.name}</span>
                            <div style={{display:"flex",alignItems:"center",gap:4,flexShrink:0}}>
                              {(p.zoneStreaks&&p.zoneStreaks[zk]>=2)&&<span style={{fontSize:11,color:"#f97316"}}>🔥×{p.zoneStreaks[zk]}</span>}
                              <span style={{color:z.color,fontSize:13,fontWeight:700}}>{z.icon} {p.zoneScores[zk]||50}</span>
                            </div>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>

                  </>}
                </div>
              );
            })():(
              ZK.map(zk=>{
                const z=ZONES[zk]; const zl=zn(zk); const q=queues[zk]||[]; const game=activeGames[zk];
                const allInGame=game?(game.participants||[...(game.teamA||[]),...(game.teamB||[])]).length:0;
                const isDisabled=(arenaState.disabledZones||[]).includes(zk);
                return(
                  <div key={zk} style={{position:"relative",marginBottom:0}}>
                    {/* Contenu de la carte — opaque si désactivée */}
                    <div style={{...S.card(),border:"1px solid "+(isDisabled?"#1f2937":z.border),
                      opacity:isDisabled?0.4:1,marginBottom:0}}
                      onClick={()=>{if(!isDisabled){setSelectedStation(zk);setStationTab("live");}}}
                      onMouseEnter={e=>{if(!isDisabled)e.currentTarget.style.borderColor=z.color;}}
                      onMouseLeave={e=>{e.currentTarget.style.borderColor=isDisabled?"#1f2937":z.border;}}>
                      <div style={{...S.row(),justifyContent:"space-between",cursor:isDisabled?"default":"pointer",paddingRight:100}}>
                        <div style={{...S.row()}}>
                          <span style={{fontSize:20}}>{z.icon}</span>
                          <div>
                            <div style={{color:"#fff",fontWeight:700,fontSize:14}}>{zl.name}</div>
                          </div>
                        </div>
                        <div style={{display:"flex",gap:6,alignItems:"center"}}>
                          {!isDisabled&&<div style={{...S.tag(z.color)}}>{q.length} en file</div>}
                          {!isDisabled&&game&&<div className="pulse-lime" style={{...S.tag("#dc2626")}}>{allInGame} LIVE</div>}
                          {!isDisabled&&<span style={{color:"#4b5563",fontSize:16}}>›</span>}
                        </div>
                      </div>
                    </div>
                    {/* Bouton toggle — toujours visible, hors de l'opacité */}
                    <button onClick={()=>onToggleZone(zk)}
                      style={{position:"absolute",top:"50%",right:12,transform:"translateY(-50%)",
                        padding:"5px 12px",borderRadius:20,border:"none",cursor:"pointer",
                        fontSize:10,fontWeight:700,zIndex:3,
                        background:isDisabled?"#ef444420":"#84cc1620",
                        color:isDisabled?"#ef4444":"#84cc16",
                        border:"1px solid "+(isDisabled?"#ef444440":"#84cc1640")}}
                      onMouseEnter={e=>{e.currentTarget.style.background=isDisabled?"#ef444430":"#84cc1630";}}
                      onMouseLeave={e=>{e.currentTarget.style.background=isDisabled?"#ef444420":"#84cc1620";}}>
                      {isDisabled?"⏸ DÉSACTIVÉ":"● LIVE"}
                    </button>
                  </div>
                );
              })
            )}
          </div>
        )}

        {tab==="players"&&(
          <div className="anim-up">
            {/* Legend */}
            <div style={{display:"flex",gap:10,flexWrap:"wrap",marginBottom:12,padding:"10px 12px",borderRadius:10,background:"#0d0f1a",border:"1px solid #1f2937"}}>
              <div style={{...S.label(),width:"100%",marginBottom:4}}>Legende</div>
              <div style={{...S.row(),gap:5,fontSize:12,color:"#6b7280"}}><div style={{width:8,height:8,borderRadius:"50%",background:"#22c55e",flexShrink:0}}/>Libre</div>
              <div style={{...S.row(),gap:5,fontSize:12,color:"#6b7280"}}><div style={{width:8,height:8,borderRadius:"50%",background:"#84cc16",flexShrink:0}}/>En file (1 ou 2)</div>
              <div style={{...S.row(),gap:5,fontSize:12,color:"#6b7280"}}><div style={{width:8,height:8,borderRadius:"50%",background:"#fbbf24",flexShrink:0}}/>En partie</div>
              <div style={{fontSize:12,color:"#6b7280"}}>| Boutons <strong style={{color:"#fff"}}>+ Zone</strong> = ajouter a cette file</div>
              <div style={{fontSize:12,color:"#6b7280"}}>| Bouton <strong style={{color:"#ef4444"}}>Retirer</strong> = sortir de la file</div>
            </div>

            {/* Filter bar */}
            <div style={{...S.label(),marginBottom:10}}>{players.length} joueurs — cliquez sur une zone pour ajouter</div>
            <div style={{display:"flex",flexDirection:"column",gap:6}}>
              {players.map(p=>{
                const {inQueues,playingAt}=getStatus(p.id,queues,activeGames);
                const canAdd=!playingAt&&inQueues.length<2;
                const statusDot = playingAt?"#fbbf24":inQueues.length>0?"#84cc16":"#374151";
                const statusText = playingAt
                  ?("⚡ En partie · "+zn(playingAt).name)
                  :inQueues.length>0
                    ?("En file · "+inQueues.map(z=>zn(z).sn).join(" + "))
                    :"Libre";
                const statusColor = playingAt?"#fbbf24":inQueues.length>0?"#84cc16":"#4b5563";
                const zonesNotIn=ZK.filter(zk=>!inQueues.includes(zk));

                return(
                  <div key={p.id} style={{borderRadius:12,background:"#0d0f1a",overflow:"hidden",
                    border:"1px solid "+(playingAt?"#fbbf2430":inQueues.length>0?"#84cc1630":"#1f2937")}}>

                    {/* Top row: identity + status + points + dossier link — full row is clickable */}
                    <div style={{...S.row(),padding:"9px 12px",gap:10}}>
                      <div style={{width:8,height:8,borderRadius:"50%",background:statusDot,flexShrink:0,marginTop:1}}/>
                      <Bib n={p.number} size="sm"/>
                      <div style={{flex:1,minWidth:0}}>
                        <div style={{color:"#fff",fontWeight:600,fontSize:13,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{p.name}</div>
                        <div style={{fontSize:11,marginTop:1,fontWeight:600,color:statusColor}}>{statusText}</div>
                      </div>
                      <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:16,color:"#84cc16",flexShrink:0}}>{p.globalPoints} pts</div>
                      <button onClick={(e)=>{e.stopPropagation();openDossier(p.id);}}
                        style={{...S.btn("#1f2937"),padding:"4px 8px",fontSize:11,flexShrink:0}}>Profil</button>
                      <button onClick={(e)=>{e.stopPropagation();if(window.confirm("Supprimer "+p.name+" de la session ?"))onRemovePlayer&&onRemovePlayer(p.id);}}
                        style={{...S.btn("#ef444420"),padding:"4px 8px",fontSize:11,color:"#ef4444",border:"1px solid #ef444440",flexShrink:0}}
                        onMouseEnter={e=>e.currentTarget.style.background="#ef444435"}
                        onMouseLeave={e=>e.currentTarget.style.background="#ef444420"}>Supprimer</button>
                    </div>

                    {/* Action row - only if not playing */}
                    {!playingAt&&(
                      <div style={{padding:"0 12px 9px 12px",display:"flex",gap:6,flexWrap:"wrap",alignItems:"center"}}>

                        {/* Current queues with remove button */}
                        {inQueues.map(z=>(
                          <div key={z} style={{...S.row(),gap:4,padding:"3px 8px 3px 6px",borderRadius:20,
                            background:ZONES[z].color+"22",border:"1px solid "+ZONES[z].color+"50"}}>
                            <span style={{fontSize:13}}>{ZONES[z].icon}</span>
                            <span style={{fontSize:11,fontWeight:600,color:ZONES[z].color}}>{zn(z).sn}</span>
                            <button onClick={()=>onRemoveQ(p.id,z)} title={"Retirer de "+zn(z).name}
                              style={{background:"none",border:"none",cursor:"pointer",color:ZONES[z].color,
                                fontSize:14,lineHeight:1,padding:0,marginLeft:2,opacity:.7}}
                              onMouseEnter={e=>e.target.style.opacity="1"}
                              onMouseLeave={e=>e.target.style.opacity=".7"}>×</button>
                          </div>
                        ))}

                        {/* Divider if both queues and add buttons */}
                        {inQueues.length>0&&canAdd&&(
                          <div style={{width:1,height:16,background:"#1f2937",flexShrink:0}}/>
                        )}

                        {/* Add-to-queue buttons — labeled with zone name */}
                        {canAdd&&zonesNotIn.map(zk=>(
                          <button key={zk} onClick={()=>onAddQ(p.id,zk)}
                            title={"Ajouter a la file : "+zn(zk).name}
                            style={{...S.row(),gap:4,padding:"3px 8px",borderRadius:20,border:"1px dashed "+ZONES[zk].color+"50",
                              background:"transparent",cursor:"pointer",color:ZONES[zk].color+"99"}}
                            onMouseEnter={e=>{e.currentTarget.style.background=ZONES[zk].color+"15";e.currentTarget.style.color=ZONES[zk].color;e.currentTarget.style.borderColor=ZONES[zk].color;}}
                            onMouseLeave={e=>{e.currentTarget.style.background="transparent";e.currentTarget.style.color=ZONES[zk].color+"99";e.currentTarget.style.borderColor=ZONES[zk].color+"50";}}>
                            <span style={{fontSize:13}}>{ZONES[zk].icon}</span>
                            <span style={{fontSize:10,fontWeight:600}}>+ {zn(zk).sn}</span>
                          </button>
                        ))}
                        {!canAdd&&inQueues.length>=2&&(
                          <div style={{fontSize:11,color:"#4b5563"}}>Max 2 files atteint</div>
                        )}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {tab==="session"&&(
          <SessionPanel
            rosters={rosters}
            players={players.filter(p=>(p.groupId||"main")===activeRosterId)}
            allPlayers={allPlayers||players}
            activeRosterId={activeRosterId}
            onActivate={onActivateRoster} onSetActiveRoster={onSetActiveRoster} onUpdateRoster={onUpdateRoster}
            onDeleteRoster={onDeleteRoster}
            onAddPlayer={onAddPlayer} onCreateRoster={onCreateRoster} onRemovePlayer={onRemovePlayer} onOpenDossier={openDossier}
            rosterCodes={rosterCodes} onUpdateCodes={onUpdateCodes}
            pendingSessions={pendingSessions}
            onDismissPending={onDismissPending}
            onPromotePending={onPromotePending}
            onAddGroupToQueue={onAddGroupToQueue}
          />
        )}

        {tab==="winners"&&(()=>{
          const today=new Date().toLocaleDateString("fr-CA",{year:"numeric",month:"long",day:"numeric"});
          const ranked=[...players].sort((a,b)=>b.globalPoints-a.globalPoints);
          const top5=ranked.slice(0,5);
          const overall=ranked[0]||null;
          const activeZK=ZK.filter(zk=>!(arenaState.disabledZones||[]).includes(zk));
          const zoneChamps={};
          activeZK.forEach(zk=>{
            const played=players.filter(p=>(p.zonesPlayed||[]).includes(zk));
            if(played.length>0) zoneChamps[zk]=[...played].sort((a,b)=>(b.zoneScores[zk]||50)-(a.zoneScores[zk]||50))[0];
          });
          const zoneIcons={purinstinct:"🏟️",speed:"⚡",handAgility:"✋",footAgility:"👟",generalAgility:"🏃",iq:"🧠"};
          const zoneNames={purinstinct:"PurInstinct",speed:"Vitesse",handAgility:"Habileté Main",footAgility:"Habileté Pied",generalAgility:"Agilité",iq:"IQ de Jeu"};
          const medals=["🥇","🥈","🥉","4️⃣","5️⃣"];

          const copyText=(text)=>{ navigator.clipboard&&navigator.clipboard.writeText(text); };

          // ── Plein écran visuel ──────────────────────────────────────
          if(winnerCard){
            const {type,zk}=winnerCard;

            const saveImage=async()=>{
              if(!cardRef.current||savingCard) return;
              setSavingCard(true);
              try{
                const canvas=await html2canvas(cardRef.current,{
                  backgroundColor:"#0a0c14",scale:3,useCORS:true,
                  logging:false,removeContainer:true
                });
                const url=canvas.toDataURL("image/png");
                const a=document.createElement("a");
                a.href=url; a.download="purinstinct-gagnant.png";
                a.click();
              }catch(e){console.error(e);}
              setSavingCard(false);
            };

            const FullCard=({accent,children})=>(
              <div style={{position:"fixed",inset:0,zIndex:60,background:"rgba(0,0,0,.95)",
                display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:20}}>
                {/* Carte visuelle — capturée par html2canvas */}
                <div ref={cardRef} onClick={saveImage} style={{width:"100%",maxWidth:380,borderRadius:24,
                  background:"#0a0c14",border:"2px solid "+(accent||"#84cc16"),padding:28,
                  position:"relative",overflow:"hidden",cursor:"pointer",
                  boxShadow:"0 0 60px "+(accent||"#84cc16")+"40"}}>
                  {/* Barre couleur top */}
                  <div style={{position:"absolute",top:0,left:0,right:0,height:4,
                    background:`linear-gradient(90deg, ${accent||"#84cc16"}, ${accent||"#84cc16"}88)`}}/>
                  {/* Logo texte */}
                  <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:10,
                    color:(accent||"#84cc16")+"80",letterSpacing:3,marginBottom:16,textAlign:"center",marginTop:8}}>
                    PURINSTINCT GAMES · {today}
                  </div>
                  {children}
                  {/* Hint tap — exclu de la capture */}
                  <div data-html2canvas-ignore="true" style={{textAlign:"center",marginTop:12,fontSize:10,color:"#374151"}}>
                    Appuyez pour enregistrer
                  </div>
                </div>
                {/* Bouton retour */}
                <div style={{marginTop:16}}>
                  <button onClick={()=>setWinnerCard(null)}
                    style={{padding:"10px 24px",borderRadius:10,background:"#111827",color:"#9ca3af",
                      border:"1px solid #374151",cursor:"pointer",fontWeight:700,fontSize:13}}>
                    ← Retour
                  </button>
                </div>
              </div>
            );

            // Carte Gagnant Overall
            if(type==="overall"&&overall){
              const streaks=ZK.filter(zk=>(overall.zoneStreaks[zk]||0)>=2);
              return(
                <FullCard accent="#ca8a04"
>
                  <div style={{textAlign:"center",marginBottom:16}}>
                    <div style={{fontSize:52,lineHeight:1,marginBottom:8}}>🥇</div>
                    <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:12,
                      color:"#ca8a04",letterSpacing:3,marginBottom:6}}>GAGNANT</div>
                    <div style={{color:"#fff",fontWeight:700,fontSize:26,marginBottom:4}}>{overall.name}</div>
                    <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:48,
                      color:"#84cc16",lineHeight:1}}>{overall.globalPoints}</div>
                    <div style={{fontSize:12,color:"#4b5563",marginTop:2}}>points globaux</div>
                  </div>
                  {/* Zones */}
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:6,marginBottom:12}}>
                    {ZK.map(zk=>{
                      const played=(overall.zonesPlayed||[]).includes(zk);
                      return(
                        <div key={zk} style={{borderRadius:10,padding:"8px 6px",textAlign:"center",
                          background:played?"#1a2e05":"#111827",
                          border:"1px solid "+(played?"#84cc1650":"#1f2937")}}>
                          <div style={{fontSize:18}}>{zoneIcons[zk]}</div>
                          <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:16,
                            color:played?"#84cc16":"#374151"}}>{overall.zoneScores[zk]||50}</div>
                          <div style={{fontSize:9,color:played?"#6b7280":"#1f2937",marginTop:1}}>{zoneNames[zk].split(" ")[0]}</div>
                        </div>
                      );
                    })}
                  </div>
                  {streaks.length>0&&(
                    <div style={{display:"flex",flexWrap:"wrap",gap:6,justifyContent:"center"}}>
                      {streaks.map(zk=>(
                        <span key={zk} style={{padding:"3px 8px",borderRadius:6,background:"#f9731620",
                          color:"#f97316",fontSize:11,fontWeight:700}}>
                          🔥 {zoneNames[zk]} ×{overall.zoneStreaks[zk]}
                        </span>
                      ))}
                    </div>
                  )}
                </FullCard>
              );
            }

            // Carte Top 5
            if(type==="top5"&&top5.length>0){
              return(
                <FullCard accent="#6366f1"
>
                  <div style={{textAlign:"center",marginBottom:20}}>
                    <div style={{fontSize:42,lineHeight:1,marginBottom:6}}>🏆</div>
                    <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:12,
                      color:"#6366f1",letterSpacing:3}}>CLASSEMENT FINAL</div>
                  </div>
                  {top5.map((p,i)=>(
                    <div key={p.id} style={{display:"flex",alignItems:"center",gap:12,padding:"10px 12px",
                      borderRadius:12,marginBottom:6,
                      background:i===0?"#1a1a2e":i===1?"#12121e":i===2?"#111118":"#0d0f1a",
                      border:"1px solid "+(i===0?"#6366f140":i===1?"#6b728040":i===2?"#b4530940":"#1f2937")}}>
                      <span style={{fontSize:20,width:28,textAlign:"center"}}>{medals[i]}</span>
                      <span style={{color:"#fff",fontWeight:700,fontSize:15,flex:1}}>{p.name}</span>
                      <div style={{textAlign:"right"}}>
                        <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:22,
                          color:i===0?"#ca8a04":i===1?"#9ca3af":i===2?"#b45309":"#6b7280"}}>{p.globalPoints}</div>
                        <div style={{fontSize:9,color:"#374151"}}>pts</div>
                      </div>
                    </div>
                  ))}
                </FullCard>
              );
            }

            // Carte Champion de zone
            if(type==="zone"&&zk&&zoneChamps[zk]){
              const champ=zoneChamps[zk];
              const z=ZONES[zk];
              const hasStreak=(champ.zoneStreaks[zk]||0)>=2;
              return(
                <FullCard accent={z.color}
>
                  <div style={{textAlign:"center",marginBottom:20}}>
                    <div style={{fontSize:56,lineHeight:1,marginBottom:10}}>{zoneIcons[zk]}</div>
                    <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:11,
                      color:z.color,letterSpacing:3,marginBottom:4}}>CHAMPION</div>
                    <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:18,
                      color:z.color,marginBottom:16}}>{zoneNames[zk].toUpperCase()}</div>
                    <div style={{color:"#fff",fontWeight:700,fontSize:28,marginBottom:8}}>{champ.name}</div>
                    <div style={{display:"inline-block",padding:"12px 24px",borderRadius:16,
                      background:z.color+"20",border:"2px solid "+z.color+"60"}}>
                      <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:52,
                        color:z.color,lineHeight:1}}>{champ.zoneScores[zk]||50}</div>
                      <div style={{fontSize:11,color:z.color+"80",marginTop:2}}>score de zone</div>
                    </div>
                    {hasStreak&&(
                      <div style={{marginTop:14,padding:"6px 16px",borderRadius:20,
                        background:"#f9731620",display:"inline-block"}}>
                        <span style={{color:"#f97316",fontWeight:700,fontSize:14}}>
                          🔥 Série ×{champ.zoneStreaks[zk]}
                        </span>
                      </div>
                    )}
                    <div style={{marginTop:12,fontSize:13,color:"#4b5563",fontWeight:600}}>
                      {champ.globalPoints} pts globaux
                    </div>
                  </div>
                </FullCard>
              );
            }

            return null;
          }

          // ── Liste des cartes ────────────────────────────────────────
          const ClickCard=({accent,onClick,children})=>(
            <div onClick={onClick} style={{borderRadius:16,background:"#0d0f1a",border:"2px solid "+(accent||"#84cc16"),
              padding:20,marginBottom:12,position:"relative",overflow:"hidden",cursor:"pointer"}}
              onMouseEnter={e=>{e.currentTarget.style.background="#111827";e.currentTarget.style.boxShadow="0 0 20px "+(accent||"#84cc16")+"20";}}
              onMouseLeave={e=>{e.currentTarget.style.background="#0d0f1a";e.currentTarget.style.boxShadow="none";}}>
              <div style={{position:"absolute",top:0,left:0,right:0,height:3,background:accent||"#84cc16"}}/>
              <div style={{position:"absolute",top:12,right:14,fontSize:16,color:(accent||"#84cc16")+"60"}}>↗</div>
              {children}
            </div>
          );

          return(
            <div className="anim-up">
              {/* Bouton publier */}
              <div style={{...S.card(),marginBottom:16,border:"1px solid "+(winnersPublished?"#84cc1640":"#374151"),
                display:"flex",alignItems:"center",justifyContent:"space-between",gap:12}}>
                <div>
                  <div style={{color:"#fff",fontWeight:700,fontSize:13}}>
                    {winnersPublished?"🏆 Gagnants publiés":"Publier les gagnants"}
                  </div>
                  <div style={{color:"#4b5563",fontSize:11,marginTop:2}}>
                    {winnersPublished?"Les joueurs voient les résultats dans leur classement":"Les joueurs ne voient pas encore les résultats"}
                  </div>
                </div>
                <button onClick={winnersPublished?onUnpublishWinners:onPublishWinners}
                  style={{...S.btn(winnersPublished?"#374151":"#84cc16"),padding:"8px 16px",fontSize:12,
                    color:winnersPublished?"#9ca3af":"#000",flexShrink:0}}>
                  {winnersPublished?"Retirer":"Publier"}
                </button>
              </div>

              <div style={{...S.label(),marginBottom:4}}>Cartes de résultats</div>
              <div style={{fontSize:11,color:"#4b5563",marginBottom:16}}>Appuyez sur une carte pour l'agrandir et la partager</div>

              {/* Gagnant overall */}
              {overall&&(
                <ClickCard accent="#ca8a04" onClick={()=>setWinnerCard({type:"overall"})}>
                  <div style={{...S.row(),gap:10}}>
                    <span style={{fontSize:32}}>🥇</span>
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:11,
                        color:"#ca8a04",letterSpacing:2,marginBottom:2}}>GAGNANT PURINSTINCT GAMES</div>
                      <div style={{color:"#fff",fontWeight:700,fontSize:17,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{overall.name}</div>
                      <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:22,color:"#84cc16"}}>{overall.globalPoints} pts</div>
                    </div>
                  </div>
                </ClickCard>
              )}

              {/* Top 5 */}
              {top5.length>0&&(
                <ClickCard accent="#6366f1" onClick={()=>setWinnerCard({type:"top5"})}>
                  <div style={{...S.row(),gap:10,marginBottom:10}}>
                    <span style={{fontSize:28}}>🏆</span>
                    <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:11,
                      color:"#6366f1",letterSpacing:2}}>TOP {top5.length} CLASSEMENT</div>
                  </div>
                  {top5.slice(0,3).map((p,i)=>(
                    <div key={p.id} style={{...S.row(),gap:8,padding:"3px 0"}}>
                      <span style={{fontSize:14,width:20}}>{medals[i]}</span>
                      <span style={{color:"#e5e7eb",fontSize:13,flex:1}}>{p.name}</span>
                      <span style={{color:"#84cc16",fontWeight:700,fontSize:13}}>{p.globalPoints}</span>
                    </div>
                  ))}
                  {top5.length>3&&<div style={{fontSize:11,color:"#4b5563",marginTop:4}}>+{top5.length-3} autres…</div>}
                </ClickCard>
              )}

              {/* Champions par zone — une carte par zone */}
              {ZK.filter(zk=>zoneChamps[zk]).map(zk=>{
                const champ=zoneChamps[zk];
                const z=ZONES[zk];
                return(
                  <ClickCard key={zk} accent={z.color} onClick={()=>setWinnerCard({type:"zone",zk})}>
                    <div style={{...S.row(),gap:10}}>
                      <span style={{fontSize:28,flexShrink:0}}>{zoneIcons[zk]}</span>
                      <div style={{flex:1,minWidth:0}}>
                        <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:10,
                          color:z.color,letterSpacing:2,marginBottom:2}}>CHAMPION {zoneNames[zk].toUpperCase()}</div>
                        <div style={{color:"#fff",fontWeight:700,fontSize:15,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{champ.name}</div>
                        <div style={{...S.row(),gap:6,marginTop:2}}>
                          <span style={{color:z.color,fontWeight:700,fontSize:13}}>{champ.zoneScores[zk]||50} pts zone</span>
                          {(champ.zoneStreaks[zk]||0)>=2&&<span style={{color:"#f97316",fontSize:11}}>🔥×{champ.zoneStreaks[zk]}</span>}
                        </div>
                      </div>
                    </div>
                  </ClickCard>
                );
              })}

              {ranked.length===0&&(
                <div style={{textAlign:"center",padding:"40px 0",color:"#4b5563",fontSize:13}}>
                  Aucun joueur enregistré pour l'instant.
                </div>
              )}
            </div>
          );
        })()}
      </div>
    </div>
  );
}

// ----------------------------------------------------------------
// QUEUE ITEM  (presence management + drag)
// ----------------------------------------------------------------
function QueueList({zone,qPlayers,onMoveTop,onMoveBottom,onRemove,onReorder,highlightId}){
  const z=ZONES[zone];
  const [dragIdx,setDragIdx]=useState(null);
  const [overIdx,setOverIdx]=useState(null);
  const touchRef=useRef({fromIdx:null});
  const listRef=useRef(null);

  const handleDrop=(toIdx)=>{
    if(dragIdx===null||dragIdx===toIdx){setDragIdx(null);setOverIdx(null);return;}
    const ids=qPlayers.map(p=>p.id);
    const [moved]=ids.splice(dragIdx,1);
    ids.splice(toIdx,0,moved);
    onReorder(zone,ids);
    setDragIdx(null);setOverIdx(null);
  };

  // Touch drag — démarre immédiatement sur le handle ⠿
  const handleHandleTouchStart=(e,idx)=>{
    e.preventDefault(); // empêche scroll et sélection texte
    touchRef.current.fromIdx=idx;
    setDragIdx(idx);
    navigator.vibrate&&navigator.vibrate(30);
  };

  const handleTouchMove=(e)=>{
    if(dragIdx===null) return;
    e.preventDefault();
    const touch=e.touches[0];
    const list=listRef.current;
    if(!list) return;
    const items=[...list.querySelectorAll("[data-queue-item]")];
    for(let i=0;i<items.length;i++){
      const rect=items[i].getBoundingClientRect();
      if(touch.clientY>=rect.top&&touch.clientY<=rect.bottom){
        setOverIdx(i); return;
      }
    }
  };

  const handleTouchEnd=()=>{
    if(dragIdx!==null){
      handleDrop(overIdx!==null?overIdx:dragIdx);
    }
    touchRef.current.fromIdx=null;
  };

  if(qPlayers.length===0) return(
    <div style={{textAlign:"center",padding:"28px 0",color:"#374151",fontSize:13}}>
      <div style={{fontSize:32,marginBottom:6,opacity:.25}}>⏳</div>
      {T.fr.autoRefill}
    </div>
  );

  return(
    <div ref={listRef} style={{display:"flex",flexDirection:"column",gap:5,userSelect:"none"}}
      onTouchMove={handleTouchMove} onTouchEnd={handleTouchEnd}>
      {qPlayers.map((p,idx)=>{
        const zs=p.zoneScores[zone]||50;
        const streak=p.zoneStreaks[zone]||0;
        const isOver=overIdx===idx;
        const isDragging=dragIdx===idx;
        return(
          <div key={p.id} data-queue-item="1"
            draggable
            onDragStart={()=>setDragIdx(idx)}
            onDragOver={e=>{e.preventDefault();setOverIdx(idx);}}
            onDrop={()=>handleDrop(idx)}
            onDragEnd={()=>{setDragIdx(null);setOverIdx(null);}}
            style={{...S.row(),padding:"8px 10px",borderRadius:10,
              background:p.id===highlightId?"#1a2e05":isDragging?"#1a2e05":isOver?"#1a1a2e":"#0d0f1a",
              border:p.id===highlightId?"2px solid "+z.color:isOver?"2px solid "+z.color+"80":isDragging?"2px solid #84cc1660":"1px solid transparent",
              cursor:"grab",transition:"all .15s",opacity:isDragging?0.5:1,
              animation:p.id===highlightId?"pulseLime 0.6s ease-in-out 4":"none"}}>
            {/* drag handle — toucher pour drag sur mobile */}
            <div
              onTouchStart={(e)=>handleHandleTouchStart(e,idx)}
              style={{color:isDragging?"#84cc16":"#4b5563",fontSize:20,flexShrink:0,
                cursor:"grab",touchAction:"none",padding:"0 4px 0 0",lineHeight:1}}>⠿</div>
            <div style={{fontSize:11,color:"#374151",fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,width:16,flexShrink:0}}>{idx+1}</div>
            <Bib n={p.number} size="sm" color={z.color}/>
            <span style={{fontSize:13,color:"#fff",flex:1,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{p.name}</span>
            {zone==="speed"&&<TierBadge score={zs}/>}
            {zone!=="speed"&&<div style={{...S.tag(z.color),fontFamily:"'Barlow Condensed',sans-serif",fontWeight:700}}>{zs}</div>}
            {streak>=2&&<span style={{fontSize:11,color:"#f97316",flexShrink:0}}>🔥x{streak}</span>}
            <button onClick={(e)=>{e.stopPropagation();onMoveTop(p.id,zone);}}
              style={{background:"none",border:"none",cursor:"pointer",color:"#4b5563",fontSize:16,lineHeight:1,padding:"0 2px"}}
              onMouseEnter={e=>e.target.style.color="#84cc16"}
              onMouseLeave={e=>e.target.style.color="#4b5563"}>↑</button>
            <button onClick={(e)=>{e.stopPropagation();onMoveBottom(p.id,zone);}}
              style={{background:"none",border:"none",cursor:"pointer",color:"#4b5563",fontSize:16,lineHeight:1,padding:"0 2px"}}
              onMouseEnter={e=>e.target.style.color="#f97316"}
              onMouseLeave={e=>e.target.style.color="#4b5563"}>↓</button>
            <button onClick={(e)=>{e.stopPropagation();onRemove(p.id,zone);}}
              style={{background:"none",border:"none",cursor:"pointer",color:"#374151",fontSize:16,lineHeight:1,padding:"0 2px"}}
              onMouseEnter={e=>e.target.style.color="#ef4444"}
              onMouseLeave={e=>e.target.style.color="#374151"}>×</button>
          </div>
        );
      })}
    </div>
  );
}

// ----------------------------------------------------------------
// SPRINT ACTIVE GAME
// ----------------------------------------------------------------
function SprintGameView({game,players,zone,onWinner,onRemove,onReplace}){
  const z=ZONES[zone];
  const pMap={}; players.forEach(p=>{pMap[p.id]=p;});
  const participants=game.participants||[];
  const pList=participants.map(id=>pMap[id]).filter(Boolean);
  const [selectedFirst,setSelectedFirst]=useState(null);
  const [selectedSecond,setSelectedSecond]=useState(null);

  const handleConfirm=()=>{
    if(!selectedFirst) return;
    onWinner(selectedFirst, selectedSecond||null);
    setSelectedFirst(null); setSelectedSecond(null);
  };

  return(
    <div>
      <div style={{...S.row(),justifyContent:"space-between",marginBottom:12}}>
        <div style={{...S.label()}}>{T.fr.raceInProgress} - {pList.length} {T.fr.coureurs}</div>
        <div className="pulse-lime" style={{...S.tag("#dc2626")}}>{T.fr.live}</div>
      </div>

      {/* Sprint handicap legend */}
      <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:12}}>
        {[1,2,3,4,5].map(t=>(
          <div key={t} style={{...S.tag(TIERS[t].color),fontSize:10}}>
            {TIERS[t].label} = {TIERS[t].pos}
          </div>
        ))}
      </div>

      {/* Participants */}
      <div style={{display:"flex",flexDirection:"column",gap:5,marginBottom:16}}>
        {pList.map((p,i)=>{
          const tier=getSprintTier(p.zoneScores.speed||50);
          const t=TIERS[tier];
          const streak=p.zoneStreaks[zone]||0;
          const isFirst=selectedFirst===p.id;
          const isSecond=selectedSecond===p.id;
          return(
            <div key={p.id} style={{...S.row(),padding:"8px 10px",borderRadius:10,
              background:isFirst?"#1a2e05":isSecond?"#1a1400":"#0d0f1a",
              border:"2px solid "+(isFirst?"#84cc16":isSecond?"#ca8a04":t.color+"40")}}>
              <div style={{width:24,height:24,borderRadius:6,display:"flex",alignItems:"center",justifyContent:"center",
                fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:12,
                background:t.color+"22",color:t.color,flexShrink:0}}>{i+1}</div>
              <TierBadge score={p.zoneScores.speed||50}/>
              <Bib n={p.number} size="sm" color={t.color}/>
              <span style={{flex:1,color:"#fff",fontWeight:600,fontSize:13}}>{p.name}</span>
              {isFirst&&<span style={{fontSize:11,color:"#84cc16",fontWeight:700}}>🥇 1er</span>}
              {isSecond&&<span style={{fontSize:11,color:"#ca8a04",fontWeight:700}}>🥈 2e</span>}
              {streak>=2&&<span style={{fontSize:11,color:"#f97316"}}>🔥x{streak}</span>}
              <span style={{fontSize:11,color:t.color,fontFamily:"'Barlow Condensed',sans-serif",fontWeight:700}}>{p.zoneScores.speed||50}</span>
              <button onClick={()=>onRemove(p.id)} title="Retirer de la course"
                style={{background:"none",border:"none",cursor:"pointer",color:"#374151",fontSize:16,lineHeight:1}}
                onMouseEnter={e=>e.target.style.color="#ef4444"}
                onMouseLeave={e=>e.target.style.color="#374151"}>×</button>
            </div>
          );
        })}
      </div>

      <button onClick={onReplace} style={{...S.btn(),width:"100%",padding:"8px",fontSize:12,marginBottom:14,border:"1px dashed #374151"}}>
        {T.fr.substitute}
      </button>

      {/* Sélection 1er place */}
      <div style={{...S.label(),textAlign:"center",marginBottom:8}}>
        {!selectedFirst?"🥇 Sélectionner le gagnant":"🥈 Sélectionner le 2e place (optionnel)"}
      </div>
      <div style={{display:"flex",flexWrap:"wrap",gap:8,marginBottom:10}}>
        {pList.filter(p=>p.id!==selectedSecond).map(p=>{
          const tier=getSprintTier(p.zoneScores.speed||50);
          const t=TIERS[tier];
          const isFirst=selectedFirst===p.id;
          return(
            <button key={p.id} onClick={()=>{
              if(!selectedFirst){setSelectedFirst(p.id);}
              else if(p.id===selectedFirst){setSelectedFirst(null);setSelectedSecond(null);}
              else{setSelectedSecond(p.id===selectedSecond?null:p.id);}
            }}
              style={{flex:"1 1 45%",padding:"12px 10px",borderRadius:12,border:"2px solid "+(isFirst?"#84cc16":selectedFirst?"#ca8a0460":"transparent"),cursor:"pointer",
                background:isFirst?"#84cc16":selectedFirst?t.color+"90":t.color,
                color:"#000",fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:16,
                boxShadow:"0 3px 12px "+t.color+"40"}}>
              {isFirst?"🥇 ":""}#{p.number} {p.name.split(" ")[0]}
            </button>
          );
        })}
      </div>

      {/* Confirmer */}
      {selectedFirst&&(
        <div style={{display:"flex",gap:8}}>
          <button onClick={handleConfirm}
            style={{flex:1,padding:"14px",borderRadius:12,border:"none",cursor:"pointer",
              background:"#84cc16",color:"#000",fontFamily:"'Barlow Condensed',sans-serif",fontWeight:900,fontSize:16}}>
            ✓ Confirmer{selectedSecond?" (1er + 2e)":" (1er seulement)"}
          </button>
          <button onClick={()=>{setSelectedFirst(null);setSelectedSecond(null);}}
            style={{padding:"14px 16px",borderRadius:12,border:"1px solid #374151",cursor:"pointer",
              background:"#111827",color:"#6b7280",fontSize:13}}>
            ✕
          </button>
        </div>
      )}
    </div>
  );
}

